/// Copy the DOP (geometry-covariance) scalars into *out_dop. Fails with
/// SIDEREON_STATUS_INVALID_ARGUMENT if the converged geometry was rank-deficient
/// (the engine produced no DOP).
///
/// Safety: sol must be a live solution handle; out_dop must point to a
/// SidereonDop.
#[no_mangle]
pub unsafe extern "C" fn sidereon_spp_solution_dop(
    sol: *const SidereonSppSolution,
    out_dop: *mut SidereonDop,
) -> SidereonStatus {
    ffi_boundary("sidereon_spp_solution_dop", SidereonStatus::Panic, || {
        let out_dop = c_try!(require_out(out_dop, "sidereon_spp_solution_dop", "out_dop"));
        *out_dop = SidereonDop {
            gdop: 0.0,
            pdop: 0.0,
            hdop: 0.0,
            vdop: 0.0,
            tdop: 0.0,
        };
        let sol = c_try!(require_ref(sol, "sidereon_spp_solution_dop", "solution"));
        let Some(dop) = sol.inner.dop.as_ref() else {
            set_last_error("sidereon_spp_solution_dop: geometry is rank-deficient, no DOP");
            return SidereonStatus::InvalidArgument;
        };
        *out_dop = SidereonDop {
            gdop: dop.gdop,
            pdop: dop.pdop,
            hdop: dop.hdop,
            vdop: dop.vdop,
            tdop: dop.tdop,
        };
        SidereonStatus::Ok
    })
}

/// Copy solver metadata into *out_metadata.
///
/// Safety: sol must be a live solution handle; out_metadata must point to a
/// SidereonSppMetadata.
#[no_mangle]
pub unsafe extern "C" fn sidereon_spp_solution_metadata(
    sol: *const SidereonSppSolution,
    out_metadata: *mut SidereonSppMetadata,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_spp_solution_metadata",
        SidereonStatus::Panic,
        || {
            let out_metadata = c_try!(require_out(
                out_metadata,
                "sidereon_spp_solution_metadata",
                "out_metadata"
            ));
            *out_metadata = empty_metadata();
            let sol = c_try!(require_ref(
                sol,
                "sidereon_spp_solution_metadata",
                "solution"
            ));
            let metadata = &sol.inner.metadata;
            *out_metadata = SidereonSppMetadata {
                iterations: metadata.iterations,
                converged: metadata.converged,
                status: solve_status_to_c(metadata.status),
                ionosphere_applied: metadata.ionosphere_applied,
                troposphere_applied: metadata.troposphere_applied,
                outer_iterations: metadata.outer_iterations,
                has_final_robust_scale_m: metadata.final_robust_scale_m.is_some(),
                final_robust_scale_m: metadata.final_robust_scale_m.unwrap_or(0.0),
                used_count: metadata.used_count,
                system_count: metadata.systems.len(),
                redundancy: metadata.redundancy as i64,
                raim_checkable: metadata.raim_checkable,
            };
            SidereonStatus::Ok
        },
    )
}

/// Release a solution handle. Null is a no-op. A non-null handle must come from
/// sidereon_solve_spp or sidereon_solve_spp_v2 and must be freed exactly once
/// with this function.
///
/// Safety: sol must be NULL or a live handle from sidereon_solve_spp or
/// sidereon_solve_spp_v2. Passing a handle after it has already been freed is
/// invalid.
#[no_mangle]
pub unsafe extern "C" fn sidereon_spp_solution_free(sol: *mut SidereonSppSolution) {
    ffi_boundary("sidereon_spp_solution_free", (), || {
        free_boxed(sol);
    });
}

// === Standalone DOP =========================================================

/// An ECEF line-of-sight unit vector from the receiver toward a satellite.
///
/// The design-matrix row this contributes is `[-e_x, -e_y, -e_z, 1]`. The
/// vector must be unit length to the engine's tolerance.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonLineOfSight {
    /// ECEF X component of the unit line-of-sight vector.
    pub e_x: f64,
    /// ECEF Y component of the unit line-of-sight vector.
    pub e_y: f64,
    /// ECEF Z component of the unit line-of-sight vector.
    pub e_z: f64,
}

fn empty_dop() -> SidereonDop {
    SidereonDop {
        gdop: 0.0,
        pdop: 0.0,
        hdop: 0.0,
        vdop: 0.0,
        tdop: 0.0,
    }
}

fn dop_to_c(dop: Dop) -> SidereonDop {
    SidereonDop {
        gdop: dop.gdop,
        pdop: dop.pdop,
        hdop: dop.hdop,
        vdop: dop.vdop,
        tdop: dop.tdop,
    }
}

/// Map a DOP error to a status code. Malformed inputs report
/// SIDEREON_STATUS_INVALID_ARGUMENT; a rank-deficient or singular geometry
/// (well-formed inputs the engine simply cannot turn into a finite DOP) reports
/// SIDEREON_STATUS_SOLVE.
fn map_dop_error(fn_name: &str, err: DopError) -> SidereonStatus {
    set_last_error(format!("{fn_name}: {err}"));
    match err {
        DopError::InvalidInput { .. } => SidereonStatus::InvalidArgument,
        DopError::TooFewSatellites | DopError::Singular => SidereonStatus::Solve,
    }
}

/// Compute the dilution-of-precision scalars from line-of-sight unit vectors,
/// diagonal weights, and the receiver geodetic position. Writes the result to
/// *out_dop. This is the standalone DOP entry; the buried per-solution DOP is
/// also available via sidereon_spp_solution_dop. The numbers are exactly what
/// the engine's dop kernel produces.
///
/// `los` and `weights` must each point to `count` entries (`count` at least
/// four). A rank-deficient or singular geometry returns SIDEREON_STATUS_SOLVE.
///
/// Safety: los and weights must each point to count readable entries (or be
/// NULL when count is 0); out_dop must point to a SidereonDop.
#[no_mangle]
pub unsafe extern "C" fn sidereon_dop(
    los: *const SidereonLineOfSight,
    weights: *const f64,
    count: usize,
    receiver: SidereonGeodetic,
    out_dop: *mut SidereonDop,
) -> SidereonStatus {
    ffi_boundary("sidereon_dop", SidereonStatus::Panic, || {
        let out_dop = c_try!(require_out(out_dop, "sidereon_dop", "out_dop"));
        *out_dop = empty_dop();
        let los = c_try!(require_slice(los, count, "sidereon_dop", "los"));
        let weights = c_try!(require_slice(weights, count, "sidereon_dop", "weights"));
        let receiver = c_try!(geodetic_to_wgs84("sidereon_dop", "receiver", receiver));
        let rows: Vec<LineOfSight> = los
            .iter()
            .map(|l| LineOfSight::new(l.e_x, l.e_y, l.e_z))
            .collect();
        let dop = match core_dop(&rows, weights, receiver) {
            Ok(dop) => dop,
            Err(err) => return map_dop_error("sidereon_dop", err),
        };
        *out_dop = dop_to_c(dop);
        SidereonStatus::Ok
    })
}

/// Construct an ECEF line-of-sight unit vector from topocentric azimuth and
/// elevation in degrees at the receiver, writing it to *out_los. Azimuth is
/// clockwise from geodetic north; elevation is positive above the horizon.
///
/// Safety: out_los must point to a SidereonLineOfSight.
#[no_mangle]
pub unsafe extern "C" fn sidereon_line_of_sight_from_az_el_deg(
    azimuth_deg: f64,
    elevation_deg: f64,
    receiver: SidereonGeodetic,
    out_los: *mut SidereonLineOfSight,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_line_of_sight_from_az_el_deg",
        SidereonStatus::Panic,
        || {
            let out_los = c_try!(require_out(
                out_los,
                "sidereon_line_of_sight_from_az_el_deg",
                "out_los"
            ));
            *out_los = SidereonLineOfSight {
                e_x: 0.0,
                e_y: 0.0,
                e_z: 0.0,
            };
            let receiver = c_try!(geodetic_to_wgs84(
                "sidereon_line_of_sight_from_az_el_deg",
                "receiver",
                receiver
            ));
            let los = match line_of_sight_from_az_el_deg(azimuth_deg, elevation_deg, receiver) {
                Ok(los) => los,
                Err(err) => return map_dop_error("sidereon_line_of_sight_from_az_el_deg", err),
            };
            *out_los = SidereonLineOfSight {
                e_x: los.e_x,
                e_y: los.e_y,
                e_z: los.e_z,
            };
            SidereonStatus::Ok
        },
    )
}

// === ANTEX antenna PCO/PCV ==================================================

/// Maximum byte length accepted for an ANTEX `TYPE / SERIAL` antenna id.
const MAX_ANTEX_ID_BYTES: usize = 256;
/// Maximum byte length accepted for an ANTEX frequency code (e.g. `G01`).
const MAX_ANTEX_FREQUENCY_BYTES: usize = 32;

/// A parsed ANTEX antenna-calibration product. Create with sidereon_antex_parse
/// and release with sidereon_antex_free.
pub struct SidereonAntex {
    inner: Antex,
}

/// A single ANTEX antenna calibration block (receiver or satellite), owned
/// independently of the parent product. Obtain one with sidereon_antex_antenna
/// and release it with sidereon_antenna_free.
pub struct SidereonAntenna {
    inner: Antenna,
}

/// Map an ANTEX parse or lookup error to a status code. Every ANTEX error is a
/// malformed-input condition, so they all report SIDEREON_STATUS_INVALID_ARGUMENT
/// with the detail available via sidereon_last_error_message.
fn map_antex_error(fn_name: &str, err: AntexError) -> SidereonStatus {
    set_last_error(format!("{fn_name}: {err}"));
    SidereonStatus::InvalidArgument
}

/// Parse an ANTEX 1.4 antenna-calibration byte buffer. On success writes a newly
/// owned handle to *out_antex. Release it with sidereon_antex_free. PCO/PCV
/// values are exposed in meters, exactly as the engine produces them.
///
/// Safety: data must point to len readable bytes; out_antex must point to
/// storage for a SidereonAntex*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antex_parse(
    data: *const u8,
    len: usize,
    out_antex: *mut *mut SidereonAntex,
) -> SidereonStatus {
    ffi_boundary("sidereon_antex_parse", SidereonStatus::Panic, || {
        let out_antex = c_try!(require_out(out_antex, "sidereon_antex_parse", "out_antex"));
        *out_antex = ptr::null_mut();
        let bytes = c_try!(require_slice(data, len, "sidereon_antex_parse", "data"));
        let text = match str::from_utf8(bytes) {
            Ok(text) => text,
            Err(_) => {
                set_last_error("sidereon_antex_parse: data is not valid UTF-8".to_string());
                return SidereonStatus::InvalidToken;
            }
        };
        let inner = match Antex::parse(text) {
            Ok(antex) => antex,
            Err(err) => return map_antex_error("sidereon_antex_parse", err),
        };
        write_boxed_handle(out_antex, SidereonAntex { inner });
        SidereonStatus::Ok
    })
}

/// Write the number of antenna blocks in the product to *out_count.
///
/// Safety: antex must be a live handle from sidereon_antex_parse; out_count must
/// point to a size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antex_antenna_count(
    antex: *const SidereonAntex,
    out_count: *mut usize,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_antex_antenna_count",
        SidereonStatus::Panic,
        || {
            let out_count = c_try!(require_out(
                out_count,
                "sidereon_antex_antenna_count",
                "out_count"
            ));
            *out_count = 0;
            let antex = c_try!(require_ref(antex, "sidereon_antex_antenna_count", "antex"));
            *out_count = antex.inner.antennas.len();
            SidereonStatus::Ok
        },
    )
}

/// Look up an antenna by its exact `TYPE / SERIAL` id. On success writes a newly
/// owned antenna handle to *out_antenna, or NULL if no block has that id (a
/// successful query that found nothing, not an error). Release a non-NULL handle
/// with sidereon_antenna_free.
///
/// Safety: antex must be a live handle from sidereon_antex_parse; id must be a
/// null-terminated C string; out_antenna must point to storage for a
/// SidereonAntenna*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antex_antenna(
    antex: *const SidereonAntex,
    id: *const c_char,
    out_antenna: *mut *mut SidereonAntenna,
) -> SidereonStatus {
    ffi_boundary("sidereon_antex_antenna", SidereonStatus::Panic, || {
        let out_antenna = c_try!(require_out(
            out_antenna,
            "sidereon_antex_antenna",
            "out_antenna"
        ));
        *out_antenna = ptr::null_mut();
        let antex = c_try!(require_ref(antex, "sidereon_antex_antenna", "antex"));
        let id = c_try!(parse_bounded_c_string(
            "sidereon_antex_antenna",
            "id",
            id,
            MAX_ANTEX_ID_BYTES
        ));
        if let Some(antenna) = antex.inner.antenna(&id) {
            write_boxed_handle(
                out_antenna,
                SidereonAntenna {
                    inner: antenna.clone(),
                },
            );
        }
        SidereonStatus::Ok
    })
}

/// Write the frequency-dependent phase-center offset (north/east/up, meters) for
/// `frequency` into out_neu (three doubles). Reports SIDEREON_STATUS_INVALID_ARGUMENT
/// if the antenna has no such frequency.
///
/// Safety: antenna must be a live handle from sidereon_antex_antenna; frequency
/// must be a null-terminated C string; out_neu must point to three writable
/// doubles.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antenna_pco(
    antenna: *const SidereonAntenna,
    frequency: *const c_char,
    out_neu: *mut f64,
) -> SidereonStatus {
    ffi_boundary("sidereon_antenna_pco", SidereonStatus::Panic, || {
        let antenna = c_try!(require_ref(antenna, "sidereon_antenna_pco", "antenna"));
        c_try!(require_out(out_neu, "sidereon_antenna_pco", "out_neu"));
        zero_f64_prefix(out_neu, 3, 3);
        let frequency = c_try!(parse_bounded_c_string(
            "sidereon_antenna_pco",
            "frequency",
            frequency,
            MAX_ANTEX_FREQUENCY_BYTES
        ));
        let pco = match antenna.inner.pco(&frequency) {
            Ok(pco) => pco,
            Err(err) => return map_antex_error("sidereon_antenna_pco", err),
        };
        c_try!(copy_exact_f64s(
            "sidereon_antenna_pco",
            "out_neu",
            out_neu,
            3,
            &pco
        ));
        SidereonStatus::Ok
    })
}

/// Write the frequency-dependent phase-center variation (meters) at `zenith_deg`
/// to *out_value, with the engine's linear zenith/azimuth interpolation. When
/// has_azimuth is false the no-azimuth grid is used and azimuth_deg is ignored;
/// when true azimuth_deg selects the azimuth slice (the no-azimuth grid is still
/// used if the antenna has no azimuth-dependent samples).
///
/// Safety: antenna must be a live handle from sidereon_antex_antenna; frequency
/// must be a null-terminated C string; out_value must point to a double.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antenna_pcv(
    antenna: *const SidereonAntenna,
    frequency: *const c_char,
    zenith_deg: f64,
    has_azimuth: bool,
    azimuth_deg: f64,
    out_value: *mut f64,
) -> SidereonStatus {
    ffi_boundary("sidereon_antenna_pcv", SidereonStatus::Panic, || {
        let out_value = c_try!(require_out(out_value, "sidereon_antenna_pcv", "out_value"));
        *out_value = 0.0;
        let antenna = c_try!(require_ref(antenna, "sidereon_antenna_pcv", "antenna"));
        let frequency = c_try!(parse_bounded_c_string(
            "sidereon_antenna_pcv",
            "frequency",
            frequency,
            MAX_ANTEX_FREQUENCY_BYTES
        ));
        let azimuth = if has_azimuth { Some(azimuth_deg) } else { None };
        let value = match antenna.inner.pcv(&frequency, zenith_deg, azimuth) {
            Ok(value) => value,
            Err(err) => return map_antex_error("sidereon_antenna_pcv", err),
        };
        *out_value = value;
        SidereonStatus::Ok
    })
}

/// Serialize a parsed ANTEX product back to ANTEX text. The output is not
/// null-terminated. Delegates to sidereon_core::antex::Antex::encode. Uses the
/// variable-length output contract documented at the top of the header.
///
/// Safety: antex must be a live handle from sidereon_antex_parse; out must point
/// to at least len writable bytes or be NULL when len is 0; out_written and
/// out_required must point to size_t values.
#[no_mangle]
pub unsafe extern "C" fn sidereon_antex_encode(
    antex: *const SidereonAntex,
    out: *mut u8,
    len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary("sidereon_antex_encode", SidereonStatus::Panic, || {
        c_try!(init_copy_counts(
            "sidereon_antex_encode",
            out_written,
            out_required
        ));
        let antex = c_try!(require_ref(antex, "sidereon_antex_encode", "antex"));
        let text = antex.inner.encode();
        c_try!(copy_prefix_to_c(
            "sidereon_antex_encode",
            "out",
            text.as_bytes(),
            out,
            len,
            out_written,
            out_required,
        ));
        SidereonStatus::Ok
    })
}

/// Release an antenna handle from sidereon_antex_antenna. Passing NULL is a
/// no-op.
///
