/// Write the number of JSON array elements that did not parse into an OMM object
/// at all to *out_count. These are neither records nor skipped identities (the
/// element carried no usable OMM); a nonzero count on an otherwise empty catalog
/// means the feed was malformed rather than empty.
///
/// Safety: catalog must be a live handle; out_count must point to a size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_omm_catalog_malformed_count(
    catalog: *const SidereonOmmCatalog,
    out_count: *mut usize,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_omm_catalog_malformed_count",
        SidereonStatus::Panic,
        || {
            let out_count = c_try!(require_out(
                out_count,
                "sidereon_omm_catalog_malformed_count",
                "out_count"
            ));
            *out_count = 0;
            let catalog = c_try!(require_ref(
                catalog,
                "sidereon_omm_catalog_malformed_count",
                "catalog"
            ));
            *out_count = catalog.malformed;
            SidereonStatus::Ok
        },
    )
}

/// Copy one skipped OMM entry (by zero-based index, in input order) into *out.
/// The object name itself, when present, is retrieved with
/// sidereon_omm_catalog_skipped_object_name. Fails with
/// SIDEREON_STATUS_INVALID_ARGUMENT if index is out of range (see
/// sidereon_omm_catalog_skipped_count).
///
/// Safety: catalog must be a live handle; out must point to a SidereonSkippedOmm.
#[no_mangle]
pub unsafe extern "C" fn sidereon_omm_catalog_skipped(
    catalog: *const SidereonOmmCatalog,
    index: usize,
    out: *mut SidereonSkippedOmm,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_omm_catalog_skipped",
        SidereonStatus::Panic,
        || {
            let out = c_try!(require_out(out, "sidereon_omm_catalog_skipped", "out"));
            *out = SidereonSkippedOmm {
                norad_id: 0,
                object_name_present: false,
            };
            let catalog = c_try!(require_ref(
                catalog,
                "sidereon_omm_catalog_skipped",
                "catalog"
            ));
            let Some(skipped) = catalog.inner.skipped.get(index) else {
                set_last_error(format!(
                    "sidereon_omm_catalog_skipped: index {index} out of range ({} entries)",
                    catalog.inner.skipped.len()
                ));
                return SidereonStatus::InvalidArgument;
            };
            *out = SidereonSkippedOmm {
                norad_id: skipped.norad_id,
                object_name_present: skipped.object_name.is_some(),
            };
            SidereonStatus::Ok
        },
    )
}

/// Copy the OBJECT_NAME of one skipped OMM entry (by zero-based index) into out
/// using the variable-length output contract documented at the top of the header.
/// The output is the UTF-8 name bytes and is not null-terminated. When the entry
/// carried no object name (object_name_present is false in
/// sidereon_omm_catalog_skipped), *out_required is 0 and nothing is written. Fails
/// with SIDEREON_STATUS_INVALID_ARGUMENT if index is out of range.
///
/// Safety: catalog must be a live handle; out must point to at least len writable
/// bytes or be NULL when len is 0; out_written and out_required must point to
/// size_t values.
#[no_mangle]
pub unsafe extern "C" fn sidereon_omm_catalog_skipped_object_name(
    catalog: *const SidereonOmmCatalog,
    index: usize,
    out: *mut u8,
    len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_omm_catalog_skipped_object_name",
        SidereonStatus::Panic,
        || {
            c_try!(init_copy_counts(
                "sidereon_omm_catalog_skipped_object_name",
                out_written,
                out_required
            ));
            let catalog = c_try!(require_ref(
                catalog,
                "sidereon_omm_catalog_skipped_object_name",
                "catalog"
            ));
            let Some(skipped) = catalog.inner.skipped.get(index) else {
                set_last_error(format!(
                    "sidereon_omm_catalog_skipped_object_name: index {index} out of range ({} entries)",
                    catalog.inner.skipped.len()
                ));
                return SidereonStatus::InvalidArgument;
            };
            let name_bytes: &[u8] = skipped
                .object_name
                .as_deref()
                .map(str::as_bytes)
                .unwrap_or(&[]);
            c_try!(copy_prefix_to_c(
                "sidereon_omm_catalog_skipped_object_name",
                "out",
                name_bytes,
                out,
                len,
                out_written,
                out_required,
            ));
            SidereonStatus::Ok
        },
    )
}

/// Release a lenient OMM catalog handle from sidereon_omm_catalog_build_lenient.
/// Passing NULL is a no-op.
///
/// Safety: catalog must be NULL or a live handle from
/// sidereon_omm_catalog_build_lenient that has not already been freed.
#[no_mangle]
pub unsafe extern "C" fn sidereon_omm_catalog_free(catalog: *mut SidereonOmmCatalog) {
    ffi_boundary("sidereon_omm_catalog_free", (), || {
        free_boxed(catalog);
    });
}

// === Integer least-squares (LAMBDA) ambiguity kernel =======================
//
// Wraps sidereon_core::ils::{lambda_ils_search, bounded_ils_search}: the
// standalone integer-ambiguity resolution kernels. Inputs are the float
// ambiguity vector and its covariance (row-major, n x n); outputs are the best
// integer vector plus the ratio-test verdict and scores. These are pure compute
// (no engine state), exposed here so a C caller can resolve ambiguities without
// the full RTK/PPP solve.

/// Scalar outcome of an integer least-squares search. The best integer vector
/// itself is written to the caller's out_fixed buffer (n entries, parallel to the
/// input float_cycles); these are the accompanying scores and the ratio-test
/// verdict. Mirrors the scalar fields of sidereon_core::ils::IlsResult; the
/// symmetrized covariance / inverse it also carries are diagnostic and not
/// surfaced here.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonIlsResult {
    /// Whether the ratio test passes at the requested threshold (the fix is
    /// accepted).
    pub fixed_status: bool,
    /// Runner-up / best score ratio. Saturates to DBL_MAX when the best score is
    /// exactly zero with a positive runner-up; 0 when there is no runner-up.
    pub ratio: f64,
    /// Best (lowest) quadratic score.
    pub best_score: f64,
    /// True when second_best_score carries a value (a runner-up lattice point
    /// existed).
    pub second_best_present: bool,
    /// Runner-up score, valid only when second_best_present is true.
    pub second_best_score: f64,
    /// Number of lattice points evaluated.
    pub candidates_evaluated: usize,
}

fn ils_error_to_status(fn_name: &str, err: IlsError) -> SidereonStatus {
    set_last_error(format!("{fn_name}: {err}"));
    SidereonStatus::InvalidArgument
}

/// Build the n x n covariance as Vec<Vec<f64>> from a row-major C buffer of
/// n*n doubles, validating the length and that n >= 1.
unsafe fn ils_covariance_from_c(
    fn_name: &str,
    n: usize,
    covariance: *const f64,
    covariance_len: usize,
) -> Result<Vec<Vec<f64>>, SidereonStatus> {
    if n == 0 {
        set_last_error(format!("{fn_name}: n must be at least 1"));
        return Err(SidereonStatus::InvalidArgument);
    }
    let expected = n.checked_mul(n).ok_or_else(|| {
        set_last_error(format!("{fn_name}: covariance dimension {n} overflows"));
        SidereonStatus::InvalidArgument
    })?;
    if covariance_len != expected {
        set_last_error(format!(
            "{fn_name}: covariance_len {covariance_len} must equal n*n ({expected})"
        ));
        return Err(SidereonStatus::InvalidArgument);
    }
    let flat = require_slice(covariance, covariance_len, fn_name, "covariance")?;
    Ok(flat.chunks_exact(n).map(<[f64]>::to_vec).collect())
}

/// Convert an ils kernel result into the C scalar struct and copy the fixed
/// integer vector (n entries) into out_fixed.
unsafe fn write_ils_result(
    fn_name: &str,
    result: &IlsResult,
    out_fixed: *mut i64,
    out_result: *mut SidereonIlsResult,
) -> Result<(), SidereonStatus> {
    let out_result = require_out(out_result, fn_name, "out_result")?;
    *out_result = SidereonIlsResult {
        fixed_status: false,
        ratio: 0.0,
        best_score: 0.0,
        second_best_present: false,
        second_best_score: 0.0,
        candidates_evaluated: 0,
    };
    // The fixed vector length always equals the input n, so the caller sizes
    // out_fixed at n; copy_exact validates non-null and capacity.
    let n = result.fixed.len();
    if out_fixed.is_null() {
        set_last_error(format!("{fn_name}: null out_fixed"));
        return Err(SidereonStatus::NullPointer);
    }
    validate_element_count::<i64>(fn_name, "out_fixed", n)?;
    ptr::copy_nonoverlapping(result.fixed.as_ptr(), out_fixed, n);
    *out_result = SidereonIlsResult {
        fixed_status: result.fixed_status,
        ratio: result.ratio,
        best_score: result.best_score,
        second_best_present: result.second_best_score.is_some(),
        second_best_score: result.second_best_score.unwrap_or(0.0),
        candidates_evaluated: result.candidates_evaluated,
    };
    Ok(())
}

/// Resolve integer ambiguities with the LAMBDA method (the RTKLIB lambda() port):
/// the true integer-least-squares optimum and runner-up for any positive-definite
/// covariance, with no search box. float_cycles points to n float ambiguities;
/// covariance points to the row-major n x n covariance (covariance_len must equal
/// n*n). ratio_threshold is the acceptance threshold for the ratio test (a common
/// value is 3.0). On success the best integer vector is written to out_fixed (n
/// entries, parallel to float_cycles) and the scores/verdict to *out_result.
/// Fails with SIDEREON_STATUS_INVALID_ARGUMENT for a singular/degenerate
/// covariance, a dimension mismatch, or non-finite inputs (see
/// sidereon_last_error_message).
///
/// Safety: float_cycles must point to n readable doubles; covariance must point to
/// covariance_len readable doubles; out_fixed must point to at least n writable
/// int64; out_result must point to a SidereonIlsResult.
#[no_mangle]
pub unsafe extern "C" fn sidereon_lambda_ils_search(
    float_cycles: *const f64,
    n: usize,
    covariance: *const f64,
    covariance_len: usize,
    ratio_threshold: f64,
    out_fixed: *mut i64,
    out_result: *mut SidereonIlsResult,
) -> SidereonStatus {
    ffi_boundary("sidereon_lambda_ils_search", SidereonStatus::Panic, || {
        let floats = c_try!(require_slice(
            float_cycles,
            n,
            "sidereon_lambda_ils_search",
            "float_cycles"
        ));
        let cov = c_try!(ils_covariance_from_c(
            "sidereon_lambda_ils_search",
            n,
            covariance,
            covariance_len
        ));
        match lambda_ils_search(floats, &cov, ratio_threshold) {
            Ok(result) => {
                c_try!(write_ils_result(
                    "sidereon_lambda_ils_search",
                    &result,
                    out_fixed,
                    out_result
                ));
                SidereonStatus::Ok
            }
            Err(err) => ils_error_to_status("sidereon_lambda_ils_search", err),
        }
    })
}

/// Resolve integer ambiguities with a bounded lattice search: enumerate the
/// lattice within radius integers of each rounded float ambiguity, capped at
/// candidate_limit evaluations. Arguments mirror sidereon_lambda_ils_search plus
/// radius (per-ambiguity search half-width, integers) and candidate_limit (the
/// maximum lattice points to evaluate before failing). On success the best integer
/// vector is written to out_fixed (n entries) and the scores/verdict to
/// *out_result. Fails with SIDEREON_STATUS_INVALID_ARGUMENT for a singular
/// covariance, a lattice that exceeds candidate_limit or yields no candidate, a
/// dimension mismatch, or non-finite inputs.
///
/// Safety: float_cycles must point to n readable doubles; covariance must point to
/// covariance_len readable doubles; out_fixed must point to at least n writable
/// int64; out_result must point to a SidereonIlsResult.
#[no_mangle]
pub unsafe extern "C" fn sidereon_bounded_ils_search(
    float_cycles: *const f64,
    n: usize,
    covariance: *const f64,
    covariance_len: usize,
    radius: i64,
    candidate_limit: usize,
    ratio_threshold: f64,
    out_fixed: *mut i64,
    out_result: *mut SidereonIlsResult,
) -> SidereonStatus {
    ffi_boundary("sidereon_bounded_ils_search", SidereonStatus::Panic, || {
        let floats = c_try!(require_slice(
            float_cycles,
            n,
            "sidereon_bounded_ils_search",
            "float_cycles"
        ));
        let cov = c_try!(ils_covariance_from_c(
            "sidereon_bounded_ils_search",
            n,
            covariance,
            covariance_len
        ));
        match bounded_ils_search(floats, &cov, radius, candidate_limit, ratio_threshold) {
            Ok(result) => {
                c_try!(write_ils_result(
                    "sidereon_bounded_ils_search",
                    &result,
                    out_fixed,
                    out_result
                ));
                SidereonStatus::Ok
            }
            Err(err) => ils_error_to_status("sidereon_bounded_ils_search", err),
        }
    })
}

// ---------------------------------------------------------------------------
// Product-staleness selection and broadcast/precise fallback.
//
// These wrap sidereon_core::staleness (graceful degradation for time-varying
// IONEX/SP3 products) and sidereon_core::positioning broadcast SPP + fallback.
// They are thin: the selection and the solve are the engine's, and a degraded or
// substituted answer always carries its staleness/source provenance rather than
// being silenced. Fetching the products over the network is the caller's job; the
// existing data/fetch surface covers it, and these entry points are pure compute.
// ---------------------------------------------------------------------------

/// How a staleness selection's source epoch relates to the requested epoch.
/// Mirrors sidereon_core::staleness::DegradationKind.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonDegradationKind {
    /// A product covering the requested epoch was present; no degradation.
    Exact = 0,
    /// No product covered the requested epoch; the most-recent prior product was
    /// used as-is (the SP3 nearest-prior path).
    NearestPrior = 1,
    /// No product covered the requested day; a prior day's IONEX grid was advanced
    /// by whole days onto the requested epoch (diurnal persistence).
    DiurnalShift = 2,
}

/// Staleness provenance attached to every selection result and to a precise
/// fallback fix. Epoch fields are seconds since the J2000 epoch; staleness_s is
/// requested - source and is never negative.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonStalenessMetadata {
    /// Which degradation path produced the result.
    pub kind: SidereonDegradationKind,
    /// The requested epoch, J2000 seconds (the most-stale epoch of a range).
    pub requested_epoch_j2000_s: f64,
    /// The source product epoch the result is backed by, J2000 seconds.
    pub source_epoch_j2000_s: f64,
    /// Staleness requested - source, seconds. Zero for an exact result.
    pub staleness_s: f64,
    /// Staleness in days (staleness_s / 86400).
    pub staleness_days: f64,
}

/// Configurable staleness cap for product selection. A selection that would rely
/// on a product older than max_staleness_s is rejected rather than returning data
/// past the cap. Build one with sidereon_staleness_policy_default / _days /
/// _seconds.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonStalenessPolicy {
    /// Maximum tolerated staleness, seconds.
    pub max_staleness_s: f64,
}

/// Typed outcome of a staleness selection. SIDEREON_SELECTION_STATUS_OK is the
/// only success; every other value mirrors a sidereon_core SelectionError variant
/// or a marshaling failure. A human-readable reason, with the structured detail
/// (source epoch, staleness, and cap for a beyond-cap rejection), is available
/// from sidereon_last_error_message.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonSelectionStatus {
    /// Success; the selection handle and metadata were written.
    Ok = 0,
    /// A required pointer argument was null.
    NullPointer = 1,
    /// An argument was structurally invalid (e.g. a count too large).
    InvalidArgument = 2,
    /// A satellite or string token did not parse.
    InvalidToken = 3,
    /// An internal panic reached the FFI boundary and was contained.
    Panic = 4,
    /// The product set was empty.
    EmptyProductSet = 5,
    /// The requested range was malformed (non-finite, or end before start).
    InvalidRange = 6,
    /// No product covers or precedes the requested epoch.
    NoPriorProduct = 7,
    /// The most-recent usable product is older than the staleness cap.
    BeyondStalenessCap = 8,
    /// A product in the set was malformed, or no prior product covers the range
    /// after a whole-day diurnal shift.
    InvalidProduct = 9,
    /// The staleness cap was non-finite or negative.
    InvalidPolicy = 10,
    /// An epoch computation overflowed the i64 J2000-second axis.
    Overflow = 11,
}

/// Which ephemeris source produced a sourced solution. Mirrors
/// sidereon_core::positioning::FixSource (precise SP3 vs broadcast).
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonFixSourceKind {
    /// A precise SP3 product produced the fix (exact or degraded).
    Precise = 0,
    /// The broadcast ephemeris path produced the fix.
    Broadcast = 1,
}

/// Why the fallback produced a fix from broadcast ephemeris. Mirrors
/// sidereon_core::positioning::BroadcastReason.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonBroadcastReasonKind {
    /// The precise staleness selection declined outright; the carried selection
    /// status is the exact reason.
    PreciseUnavailable = 0,
    /// A stale (within-cap) precise product was selected but could not serve the
    /// requested epoch, so broadcast was used; the attempted product's staleness
    /// is carried.
    PreciseDegradedUnusable = 1,
}

/// Typed outcome of sidereon_solve_with_fallback. SIDEREON_FALLBACK_STATUS_OK is
/// the only success; PreciseSolve / BroadcastSolve name which path's SPP solve
/// failed (FallbackError::Precise / ::Broadcast). The reason is available from
/// sidereon_last_error_message.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonFallbackStatus {
    /// Success; the sourced-solution handle was written.
    Ok = 0,
    /// A required pointer argument was null.
    NullPointer = 1,
    /// An argument was structurally invalid.
    InvalidArgument = 2,
    /// A satellite or string token did not parse.
    InvalidToken = 3,
    /// An internal panic reached the FFI boundary and was contained.
    Panic = 4,
    /// A usable precise product was selected but its SPP solve failed
    /// (FallbackError::Precise); broadcast is not silently re-solved in this case.
    PreciseSolve = 5,
    /// The broadcast fallback path was taken and its SPP solve failed
    /// (FallbackError::Broadcast).
    BroadcastSolve = 6,
}

/// A broadcast (navigation-message) ephemeris source for the supported real-time
/// / offline SPP mode. Opaque to C. Create with
/// sidereon_broadcast_ephemeris_parse_nav and release with
/// sidereon_broadcast_ephemeris_free.
pub struct SidereonBroadcastEphemeris {
    inner: BroadcastEphemeris,
}

/// A receiver solution paired with the ephemeris-source provenance that produced
/// it. Opaque to C. Create with sidereon_solve_with_fallback and release with
/// sidereon_sourced_solution_free.
pub struct SidereonSourcedSolution {
    solution: ReceiverSolution,
    source: FixSource,
}

fn degradation_kind_to_c(kind: DegradationKind) -> SidereonDegradationKind {
    match kind {
        DegradationKind::Exact => SidereonDegradationKind::Exact,
        DegradationKind::NearestPrior => SidereonDegradationKind::NearestPrior,
        DegradationKind::DiurnalShift => SidereonDegradationKind::DiurnalShift,
    }
}

fn staleness_metadata_to_c(metadata: StalenessMetadata) -> SidereonStalenessMetadata {
    SidereonStalenessMetadata {
        kind: degradation_kind_to_c(metadata.kind),
        requested_epoch_j2000_s: metadata.requested_epoch_j2000_s,
        source_epoch_j2000_s: metadata.source_epoch_j2000_s,
        staleness_s: metadata.staleness_s,
        staleness_days: metadata.staleness_days,
    }
}

fn empty_staleness_metadata() -> SidereonStalenessMetadata {
    SidereonStalenessMetadata {
        kind: SidereonDegradationKind::Exact,
        requested_epoch_j2000_s: 0.0,
        source_epoch_j2000_s: 0.0,
        staleness_s: 0.0,
        staleness_days: 0.0,
    }
}

/// Map a typed selection error to its C status without touching last_error.
/// Use this when the selection error is provenance to be surfaced on a
/// successful readout, not the cause of a failing return.
fn selection_error_to_status(err: &SelectionError) -> SidereonSelectionStatus {
    match err {
        SelectionError::EmptyProductSet => SidereonSelectionStatus::EmptyProductSet,
        SelectionError::InvalidRange { .. } => SidereonSelectionStatus::InvalidRange,
        SelectionError::NoPriorProduct { .. } => SidereonSelectionStatus::NoPriorProduct,
        SelectionError::BeyondStalenessCap { .. } => SidereonSelectionStatus::BeyondStalenessCap,
        SelectionError::InvalidProduct(_) => SidereonSelectionStatus::InvalidProduct,
        SelectionError::InvalidPolicy { .. } => SidereonSelectionStatus::InvalidPolicy,
        SelectionError::Overflow { .. } => SidereonSelectionStatus::Overflow,
    }
}

/// Map a typed selection error to its C status on a failing return, recording
/// its Display (which carries the structured detail) for
/// sidereon_last_error_message.
fn map_selection_error(fn_name: &str, err: &SelectionError) -> SidereonSelectionStatus {
    set_last_error(format!("{fn_name}: {err}"));
    selection_error_to_status(err)
}

/// Map a marshaling status onto the selection status surface.
fn marshal_status_to_selection(status: SidereonStatus) -> SidereonSelectionStatus {
    match status {
        SidereonStatus::Ok => SidereonSelectionStatus::Ok,
        SidereonStatus::NullPointer => SidereonSelectionStatus::NullPointer,
        SidereonStatus::InvalidToken => SidereonSelectionStatus::InvalidToken,
        SidereonStatus::Panic => SidereonSelectionStatus::Panic,
        SidereonStatus::InvalidArgument | SidereonStatus::Sp3Parse | SidereonStatus::Solve => {
            SidereonSelectionStatus::InvalidArgument
        }
    }
}

/// Map a marshaling status onto the fallback status surface.
fn marshal_status_to_fallback(status: SidereonStatus) -> SidereonFallbackStatus {
    match status {
        SidereonStatus::Ok => SidereonFallbackStatus::Ok,
        SidereonStatus::NullPointer => SidereonFallbackStatus::NullPointer,
        SidereonStatus::InvalidToken => SidereonFallbackStatus::InvalidToken,
        SidereonStatus::Panic => SidereonFallbackStatus::Panic,
        SidereonStatus::InvalidArgument | SidereonStatus::Sp3Parse | SidereonStatus::Solve => {
            SidereonFallbackStatus::InvalidArgument
        }
    }
}

macro_rules! sel_try {
    ($expr:expr) => {
        match $expr {
            Ok(value) => value,
            Err(status) => return marshal_status_to_selection(status),
        }
    };
}

macro_rules! fb_try {
    ($expr:expr) => {
        match $expr {
            Ok(value) => value,
            Err(status) => return marshal_status_to_fallback(status),
        }
    };
}

/// Collect an array of SP3 handle pointers into an owned product slice the engine
/// can select over. A zero count yields an empty set (so the engine reports
/// EmptyProductSet), matching the core contract.
unsafe fn sp3_products_from_c(
    fn_name: &str,
    products: *const *const SidereonSp3,
    product_count: usize,
) -> Result<Vec<Sp3>, SidereonStatus> {
    let raw = require_slice(products, product_count, fn_name, "products")?;
    let mut set = Vec::with_capacity(raw.len());
    for (idx, &handle_ptr) in raw.iter().enumerate() {
        let handle = require_ref(handle_ptr, fn_name, &format!("products[{idx}]"))?;
        set.push(handle.inner.clone());
    }
    Ok(set)
}

/// Collect an array of IONEX handle pointers into an owned product slice.
unsafe fn ionex_products_from_c(
    fn_name: &str,
    products: *const *const SidereonIonex,
    product_count: usize,
) -> Result<Vec<Ionex>, SidereonStatus> {
    let raw = require_slice(products, product_count, fn_name, "products")?;
    let mut set = Vec::with_capacity(raw.len());
    for (idx, &handle_ptr) in raw.iter().enumerate() {
        let handle = require_ref(handle_ptr, fn_name, &format!("products[{idx}]"))?;
        set.push(handle.inner.clone());
    }
    Ok(set)
}

/// A staleness policy with the engine default cap (3 days).
#[no_mangle]
pub extern "C" fn sidereon_staleness_policy_default() -> SidereonStalenessPolicy {
    SidereonStalenessPolicy {
        max_staleness_s: StalenessPolicy::default().max_staleness_s,
    }
}

/// A staleness policy with a cap expressed in days.
#[no_mangle]
pub extern "C" fn sidereon_staleness_policy_days(days: f64) -> SidereonStalenessPolicy {
    SidereonStalenessPolicy {
        max_staleness_s: StalenessPolicy::days(days).max_staleness_s,
    }
}

/// A staleness policy with a cap expressed in seconds.
#[no_mangle]
pub extern "C" fn sidereon_staleness_policy_seconds(seconds: f64) -> SidereonStalenessPolicy {
    SidereonStalenessPolicy {
        max_staleness_s: StalenessPolicy::seconds(seconds).max_staleness_s,
    }
}

/// Select an SP3 product usable across the range [start, end] (J2000 seconds),
/// degrading to the most-recent prior product within policy. On success writes a
/// newly owned clone of the selected product to *out_selection (a SidereonSp3
/// usable with the SP3 interpolation accessors and released with
/// sidereon_sp3_free) and the staleness provenance to *out_metadata. For an exact
/// selection the clone is byte-identical to the caller's product, so interpolating
/// it reproduces the engine bit-for-bit.
///
/// Safety: products must point to product_count readable SidereonSp3 pointers (or
/// be NULL when product_count is 0); out_selection and out_metadata must point to
/// writable storage of the documented type.
#[no_mangle]
pub unsafe extern "C" fn sidereon_select_sp3_over_range(
    products: *const *const SidereonSp3,
    product_count: usize,
    start_epoch_j2000_s: f64,
    end_epoch_j2000_s: f64,
    policy: SidereonStalenessPolicy,
    out_selection: *mut *mut SidereonSp3,
    out_metadata: *mut SidereonStalenessMetadata,
) -> SidereonSelectionStatus {
    ffi_boundary(
        "sidereon_select_sp3_over_range",
        SidereonSelectionStatus::Panic,
        || {
            let out_selection = sel_try!(require_out(
                out_selection,
                "sidereon_select_sp3_over_range",
                "out_selection"
            ));
            *out_selection = ptr::null_mut();
            let out_metadata = sel_try!(require_out(
                out_metadata,
                "sidereon_select_sp3_over_range",
                "out_metadata"
            ));
            *out_metadata = empty_staleness_metadata();
            let set = sel_try!(sp3_products_from_c(
                "sidereon_select_sp3_over_range",
                products,
                product_count
            ));
            let policy = StalenessPolicy {
                max_staleness_s: policy.max_staleness_s,
            };
            match select_sp3_over_range(&set, start_epoch_j2000_s, end_epoch_j2000_s, policy) {
                Ok(selection) => {
                    *out_metadata = staleness_metadata_to_c(selection.metadata());
                    write_boxed_handle(
                        out_selection,
                        SidereonSp3 {
                            inner: selection.sp3().clone(),
                        },
                    );
                    SidereonSelectionStatus::Ok
                }
                Err(err) => map_selection_error("sidereon_select_sp3_over_range", &err),
            }
        },
    )
}

/// Single-epoch convenience over sidereon_select_sp3_over_range.
