// ===========================================================================
// Predicted observables (line of sight, range rate, Doppler, az/el) from an SP3
// or broadcast source. Delegates to sidereon_core::observables::predict.
// ===========================================================================

/// Predictor options. Initialize with sidereon_observables_options_init for the
/// engine defaults (L1 carrier, light-time and Sagnac corrections on).
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonObservablesOptions {
    /// Carrier frequency in hertz used for the Doppler conversion.
    pub carrier_hz: f64,
    /// Apply fixed-point light-time correction in the geometry substrate.
    pub light_time: bool,
    /// Apply Earth-rotation Sagnac correction in the geometry substrate.
    pub sagnac: bool,
}

/// One satellite's predicted observables at one epoch.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonPredictedObservables {
    /// Geometric range, meters.
    pub geometric_range_m: f64,
    /// Range rate (positive receding), meters per second.
    pub range_rate_m_s: f64,
    /// Doppler shift at options.carrier_hz, hertz.
    pub doppler_hz: f64,
    /// Whether sat_clock_s is present.
    pub has_sat_clock_s: bool,
    /// Satellite clock offset, seconds, when present.
    pub sat_clock_s: f64,
    /// Topocentric elevation, degrees.
    pub elevation_deg: f64,
    /// Topocentric azimuth, degrees in [0, 360).
    pub azimuth_deg: f64,
    /// Transmit-time offset from the receive epoch, microseconds.
    pub transmit_offset_us: i64,
    /// Transmit time, seconds since J2000.
    pub transmit_time_j2000_s: f64,
    /// ECEF line-of-sight unit vector (receiver toward satellite).
    pub los_unit: [f64; 3],
    /// Satellite ECEF position, meters.
    pub sat_pos_ecef_m: [f64; 3],
    /// Satellite ECEF velocity, meters per second.
    pub sat_velocity_m_s: [f64; 3],
}

fn map_observables_error(fn_name: &str, err: ObservablesError) -> SidereonStatus {
    set_last_error(format!("{fn_name}: {err}"));
    match err {
        ObservablesError::InvalidInput { .. } => SidereonStatus::InvalidArgument,
        ObservablesError::NoEphemeris | ObservablesError::Ephemeris(_) => SidereonStatus::Solve,
    }
}

fn predicted_observables_to_c(obs: &PredictedObservables) -> SidereonPredictedObservables {
    SidereonPredictedObservables {
        geometric_range_m: obs.geometric_range_m,
        range_rate_m_s: obs.range_rate_m_s,
        doppler_hz: obs.doppler_hz,
        has_sat_clock_s: obs.sat_clock_s.is_some(),
        sat_clock_s: obs.sat_clock_s.unwrap_or(0.0),
        elevation_deg: obs.elevation_deg,
        azimuth_deg: obs.azimuth_deg,
        transmit_offset_us: obs.transmit_offset_us,
        transmit_time_j2000_s: obs.transmit_time_j2000_s,
        los_unit: obs.los_unit,
        sat_pos_ecef_m: obs.sat_pos_ecef_m,
        sat_velocity_m_s: obs.sat_velocity_m_s,
    }
}

unsafe fn predict_options_from_c(
    fn_name: &str,
    options: *const SidereonObservablesOptions,
) -> Result<PredictOptions, SidereonStatus> {
    if options.is_null() {
        return Ok(PredictOptions::default());
    }
    let options = require_ref(options, fn_name, "options")?;
    Ok(PredictOptions {
        carrier_hz: options.carrier_hz,
        light_time: options.light_time,
        sagnac: options.sagnac,
    })
}

/// Populate *out_options with the engine's default predictor options (L1
/// carrier, light-time and Sagnac corrections on).
///
/// Safety: out_options must point to a SidereonObservablesOptions.
#[no_mangle]
pub unsafe extern "C" fn sidereon_observables_options_init(
    out_options: *mut SidereonObservablesOptions,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_observables_options_init",
        SidereonStatus::Panic,
        || {
            let out_options = c_try!(require_out(
                out_options,
                "sidereon_observables_options_init",
                "out_options"
            ));
            let defaults = PredictOptions::default();
            *out_options = SidereonObservablesOptions {
                carrier_hz: defaults.carrier_hz,
                light_time: defaults.light_time,
                sagnac: defaults.sagnac,
            };
            SidereonStatus::Ok
        },
    )
}

/// Predict one satellite's observables from a loaded SP3 product. Delegates to
/// sidereon_core::observables::predict. options may be NULL for the engine
/// defaults.
///
/// Safety: sp3 must be a live handle; sat_id must be a null-terminated token;
/// receiver_ecef_m must point to three readable doubles; options must be NULL or
/// point to a SidereonObservablesOptions; out must point to a
/// SidereonPredictedObservables.
#[no_mangle]
pub unsafe extern "C" fn sidereon_sp3_observables(
    sp3: *const SidereonSp3,
    sat_id: *const c_char,
    receiver_ecef_m: *const f64,
    t_rx_j2000_s: f64,
    options: *const SidereonObservablesOptions,
    out: *mut SidereonPredictedObservables,
) -> SidereonStatus {
    ffi_boundary("sidereon_sp3_observables", SidereonStatus::Panic, || {
        let out = c_try!(require_out(out, "sidereon_sp3_observables", "out"));
        let sp3 = c_try!(require_ref(sp3, "sidereon_sp3_observables", "sp3"));
        let satellite = c_try!(parse_satellite_token("sidereon_sp3_observables", sat_id));
        let receiver = c_try!(require_slice(
            receiver_ecef_m,
            3,
            "sidereon_sp3_observables",
            "receiver_ecef_m"
        ));
        let receiver_ecef_m = [receiver[0], receiver[1], receiver[2]];
        let opts = c_try!(predict_options_from_c("sidereon_sp3_observables", options));
        let obs =
            match observables_predict(&sp3.inner, satellite, receiver_ecef_m, t_rx_j2000_s, opts) {
                Ok(obs) => obs,
                Err(err) => return map_observables_error("sidereon_sp3_observables", err),
            };
        *out = predicted_observables_to_c(&obs);
        SidereonStatus::Ok
    })
}

/// Predict one satellite's observables from a loaded broadcast (navigation
/// message) source. Delegates to sidereon_core::observables::predict. options
/// may be NULL for the engine defaults.
///
/// Safety: broadcast must be a live handle from
/// sidereon_broadcast_ephemeris_parse_nav; sat_id must be a null-terminated
/// token; receiver_ecef_m must point to three readable doubles; options must be
/// NULL or point to a SidereonObservablesOptions; out must point to a
/// SidereonPredictedObservables.
#[no_mangle]
pub unsafe extern "C" fn sidereon_broadcast_observables(
    broadcast: *const SidereonBroadcastEphemeris,
    sat_id: *const c_char,
    receiver_ecef_m: *const f64,
    t_rx_j2000_s: f64,
    options: *const SidereonObservablesOptions,
    out: *mut SidereonPredictedObservables,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_broadcast_observables",
        SidereonStatus::Panic,
        || {
            let out = c_try!(require_out(out, "sidereon_broadcast_observables", "out"));
            let broadcast = c_try!(require_ref(
                broadcast,
                "sidereon_broadcast_observables",
                "broadcast"
            ));
            let satellite = c_try!(parse_satellite_token(
                "sidereon_broadcast_observables",
                sat_id
            ));
            let receiver = c_try!(require_slice(
                receiver_ecef_m,
                3,
                "sidereon_broadcast_observables",
                "receiver_ecef_m"
            ));
            let receiver_ecef_m = [receiver[0], receiver[1], receiver[2]];
            let opts = c_try!(predict_options_from_c(
                "sidereon_broadcast_observables",
                options
            ));
            let obs = match observables_predict(
                &broadcast.inner,
                satellite,
                receiver_ecef_m,
                t_rx_j2000_s,
                opts,
            ) {
                Ok(obs) => obs,
                Err(err) => return map_observables_error("sidereon_broadcast_observables", err),
            };
            *out = predicted_observables_to_c(&obs);
            SidereonStatus::Ok
        },
    )
}

/// Solve receiver ECEF velocity and clock drift from one epoch of range-rate or
/// Doppler observations against a broadcast source. Mirror of
/// sidereon_solve_velocity for the broadcast (navigation message) source; it
/// produces the same SidereonVelocitySolution handle, so the
/// sidereon_velocity_solution_* accessors and sidereon_velocity_solution_free
/// apply unchanged. Delegates to sidereon::solve_velocity.
///
/// Safety: broadcast must be a live handle from
/// sidereon_broadcast_ephemeris_parse_nav; observations must point to count
/// entries (each with a valid sat_id); receiver_ecef_m must point to three
/// readable doubles; options must be NULL or point to a SidereonVelocityOptions;
/// out_solution must point to storage for a SidereonVelocitySolution*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_solve_velocity_broadcast(
    broadcast: *const SidereonBroadcastEphemeris,
    observations: *const SidereonVelocityObservation,
    count: usize,
    receiver_ecef_m: *const f64,
    t_rx_j2000_s: f64,
    options: *const SidereonVelocityOptions,
    out_solution: *mut *mut SidereonVelocitySolution,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_solve_velocity_broadcast",
        SidereonStatus::Panic,
        || {
            let out_solution = c_try!(require_out(
                out_solution,
                "sidereon_solve_velocity_broadcast",
                "out_solution"
            ));
            *out_solution = ptr::null_mut();
            let broadcast = c_try!(require_ref(
                broadcast,
                "sidereon_solve_velocity_broadcast",
                "broadcast"
            ));
            let raw = c_try!(require_slice(
                observations,
                count,
                "sidereon_solve_velocity_broadcast",
                "observations"
            ));
            let receiver = c_try!(require_slice(
                receiver_ecef_m,
                3,
                "sidereon_solve_velocity_broadcast",
                "receiver_ecef_m"
            ));
            let receiver_ecef_m = [receiver[0], receiver[1], receiver[2]];

            let core_options = if options.is_null() {
                VelocitySolveOptions::default()
            } else {
                let options = c_try!(require_ref(
                    options,
                    "sidereon_solve_velocity_broadcast",
                    "options"
                ));
                VelocitySolveOptions {
                    observable: c_try!(velocity_observable_from_c(
                        "sidereon_solve_velocity_broadcast",
                        "options.observable",
                        options.observable
                    )),
                    light_time: options.light_time,
                    sagnac: options.sagnac,
                }
            };

            let mut parsed = Vec::with_capacity(raw.len());
            for obs in raw {
                let satellite_id = c_try!(parse_satellite_token(
                    "sidereon_solve_velocity_broadcast",
                    obs.sat_id
                ));
                parsed.push(VelocityObservation {
                    satellite_id,
                    value: obs.value,
                    carrier_hz: obs.carrier_hz,
                    sat_clock_drift_s_s: obs.sat_clock_drift_s_s,
                });
            }

            let inner = c_try!(guard(SidereonStatus::Solve, || {
                sidereon::solve_velocity(
                    &broadcast.inner,
                    &parsed,
                    receiver_ecef_m,
                    t_rx_j2000_s,
                    core_options,
                )
            }));
            write_boxed_handle(out_solution, SidereonVelocitySolution { inner });
            SidereonStatus::Ok
        },
    )
}

// ===========================================================================
// Reduced-orbit (compact mean-element) fit / evaluation / drift. Delegates to
// sidereon_core::orbit::{fit_with_model, position, position_velocity, drift}.
// ===========================================================================

/// Which mean-element model a reduced-orbit fit/evaluation uses.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonReducedOrbitModel {
    /// Circular orbit (eccentricity fixed at zero); the engine default.
    CircularSecular = 0,
    /// Eccentric orbit via a nonsingular (h, k) parameterization.
    EccentricSecular = 1,
}

/// Reference frame a reduced-orbit position/velocity result is expressed in.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonReducedOrbitFrame {
    /// Inertial GCRS (ECI).
    Gcrs = 0,
    /// Earth-fixed ITRF/IGS ECEF.
    Ecef = 1,
}

/// A UTC calendar instant (year, month, day, hour, minute, fractional second).
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonCalendarEpoch {
    /// Calendar year.
    pub year: i32,
    /// Calendar month, 1-12.
    pub month: i32,
    /// Calendar day of month, 1-31.
    pub day: i32,
    /// Hour of day, 0-23.
    pub hour: i32,
    /// Minute of hour, 0-59.
    pub minute: i32,
    /// Second of minute, fractional.
    pub second: f64,
}

/// One fit/drift truth sample: a calendar epoch and an ECEF (ITRF) position.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonEcefSample {
    /// Sample epoch.
    pub epoch: SidereonCalendarEpoch,
    /// ECEF X, meters.
    pub x_m: f64,
    /// ECEF Y, meters.
    pub y_m: f64,
    /// ECEF Z, meters.
    pub z_m: f64,
}

/// Fitted reduced-orbit mean elements. The `model` field is a
/// SidereonReducedOrbitModel value (cast to uint32_t).
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonReducedOrbitElements {
    /// Model these elements belong to (SidereonReducedOrbitModel as uint32_t).
    pub model: u32,
    /// Reference epoch t0.
    pub epoch: SidereonCalendarEpoch,
    /// Semi-major axis a, meters.
    pub a_m: f64,
    /// Eccentricity.
    pub e: f64,
    /// Inclination i, radians.
    pub i_rad: f64,
    /// RAAN at t0, radians.
    pub raan_rad: f64,
    /// Fitted nodal regression rate, radians per second.
    pub raan_rate_rad_s: f64,
    /// J2 nodal-regression seed for raan_rate, radians per second.
    pub raan_rate_j2_rad_s: f64,
    /// Argument of latitude at t0, radians.
    pub arg_lat_rad: f64,
    /// Mean motion n, radians per second.
    pub mean_motion_rad_s: f64,
    /// Eccentricity vector component h = e*sin(omega).
    pub h: f64,
    /// Eccentricity vector component k = e*cos(omega).
    pub k: f64,
    /// Argument of perigee omega, radians.
    pub arg_perigee_rad: f64,
}

/// Residual statistics from a reduced-orbit fit, meters.
