// --- RINEX navigation serialize (sidereon_core::rinex_nav) -------------------

/// Serialize a parsed broadcast-ephemeris store back to RINEX navigation text.
/// The store's records are written via
/// sidereon_core::rinex_nav::encode_nav. Uses the variable-length output
/// contract: pass out=NULL/len=0 to size the buffer (out_required), then call
/// again with a buffer of at least out_required bytes.
///
/// Safety: eph is a live broadcast handle; out points to len bytes or NULL when
/// len is 0; out_written and out_required point to size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_rinex_encode_nav(
    eph: *const SidereonBroadcastEphemeris,
    out: *mut u8,
    len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary("sidereon_rinex_encode_nav", SidereonStatus::Panic, || {
        c_try!(init_copy_counts(
            "sidereon_rinex_encode_nav",
            out_written,
            out_required
        ));
        let eph = c_try!(require_ref(eph, "sidereon_rinex_encode_nav", "eph"));
        let text = sidereon_core::rinex::nav::encode_nav(eph.inner.records());
        c_try!(copy_prefix_to_c(
            "sidereon_rinex_encode_nav",
            "out",
            text.as_bytes(),
            out,
            len,
            out_written,
            out_required,
        ));
        SidereonStatus::Ok
    })
}

// --- Angles-only IOD (sidereon_core::astro::iod) -----------------------------

/// Gauss angles-only initial orbit determination. From three topocentric
/// right-ascension/declination observations (radians), their split Julian dates,
/// and the three site ECI position vectors (3x3, row i = observation i, km),
/// recover the middle observation's ECI position (km) and velocity (km/s).
/// Delegates to sidereon_core::astro::iod::gauss_angles.
///
/// Safety: decl/rtasc/jd/jdf point to 3 doubles each; rseci_km points to 9
/// doubles (row-major, row i = site i); out_position_km and out_velocity_km_s
/// point to 3 doubles each.
#[no_mangle]
pub unsafe extern "C" fn sidereon_iod_gauss_angles(
    decl_rad: *const f64,
    rtasc_rad: *const f64,
    jd: *const f64,
    jdf: *const f64,
    rseci_km: *const f64,
    out_position_km: *mut f64,
    out_velocity_km_s: *mut f64,
) -> SidereonStatus {
    ffi_boundary("sidereon_iod_gauss_angles", SidereonStatus::Panic, || {
        let out_position_km = c_try!(require_out(
            out_position_km,
            "sidereon_iod_gauss_angles",
            "out_position_km"
        ));
        let out_position_km = out_position_km as *mut f64;
        let out_velocity_km_s = c_try!(require_out(
            out_velocity_km_s,
            "sidereon_iod_gauss_angles",
            "out_velocity_km_s"
        ));
        let out_velocity_km_s = out_velocity_km_s as *mut f64;
        for idx in 0..3 {
            *out_position_km.add(idx) = 0.0;
            *out_velocity_km_s.add(idx) = 0.0;
        }
        let decl = c_try!(read_vec3("sidereon_iod_gauss_angles", "decl_rad", decl_rad));
        let rtasc = c_try!(read_vec3(
            "sidereon_iod_gauss_angles",
            "rtasc_rad",
            rtasc_rad
        ));
        let jd = c_try!(read_vec3("sidereon_iod_gauss_angles", "jd", jd));
        let jdf = c_try!(read_vec3("sidereon_iod_gauss_angles", "jdf", jdf));
        let rseci = c_try!(read_mat3("sidereon_iod_gauss_angles", "rseci_km", rseci_km));
        match sidereon_core::astro::iod::gauss_angles(&decl, &rtasc, &jd, &jdf, &rseci) {
            Ok((position, velocity)) => {
                copy_vec3(out_position_km, position);
                copy_vec3(out_velocity_km_s, velocity);
                SidereonStatus::Ok
            }
            Err(err) => extra_invalid_arg("sidereon_iod_gauss_angles", err),
        }
    })
}

// --- Ionosphere-free phase from cycles (sidereon_core::combinations) ---------

/// Ionosphere-free carrier-phase combination (meters) from cycle-valued phase
/// inputs and the two carrier frequencies (Hz). Delegates to
/// sidereon_core::combinations::ionosphere_free_phase_cycles.
///
/// Safety: out points to a double.
#[no_mangle]
pub unsafe extern "C" fn sidereon_combination_ionosphere_free_phase_cycles(
    phi1_cycles: f64,
    phi2_cycles: f64,
    f1_hz: f64,
    f2_hz: f64,
    out: *mut f64,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_combination_ionosphere_free_phase_cycles",
        SidereonStatus::Panic,
        || {
            let out = c_try!(require_out(
                out,
                "sidereon_combination_ionosphere_free_phase_cycles",
                "out"
            ));
            *out = 0.0;
            match sidereon_core::combinations::ionosphere_free_phase_cycles(
                phi1_cycles,
                phi2_cycles,
                f1_hz,
                f2_hz,
            ) {
                Ok(v) => {
                    *out = v;
                    SidereonStatus::Ok
                }
                Err(err) => {
                    extra_invalid_arg("sidereon_combination_ionosphere_free_phase_cycles", err)
                }
            }
        },
    )
}

// --- Encounter-plane covariance projection (sidereon_core::astro::conjunction)

/// Project a 3x3 ECI position covariance (km^2, row-major in cov_km2) into the 2D
/// encounter plane, writing the 2x2 result row-major into out (4 doubles).
/// Delegates to
/// sidereon_core::astro::conjunction::encounter_plane_covariance.
///
/// Safety: frame points to a SidereonEncounterFrame; cov_km2 points to 9
/// doubles; out points to 4 doubles.
#[no_mangle]
pub unsafe extern "C" fn sidereon_encounter_plane_covariance(
    frame: *const SidereonEncounterFrame,
    cov_km2: *const f64,
    out: *mut f64,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_encounter_plane_covariance",
        SidereonStatus::Panic,
        || {
            let out = c_try!(require_out(
                out,
                "sidereon_encounter_plane_covariance",
                "out"
            ));
            let out = out as *mut f64;
            for idx in 0..4 {
                *out.add(idx) = 0.0;
            }
            let frame = c_try!(require_ref(
                frame,
                "sidereon_encounter_plane_covariance",
                "frame"
            ));
            let cov = c_try!(read_mat3(
                "sidereon_encounter_plane_covariance",
                "cov_km2",
                cov_km2
            ));
            let core_frame = sidereon_core::astro::conjunction::EncounterFrame {
                x_hat: frame.x_hat,
                y_hat: frame.y_hat,
                z_hat: frame.z_hat,
                relative_position_km: frame.relative_position_km,
                relative_velocity_km_s: frame.relative_velocity_km_s,
                miss_km: frame.miss_km,
                relative_speed_km_s: frame.relative_speed_km_s,
            };
            match sidereon_core::astro::conjunction::encounter_plane_covariance(&core_frame, &cov) {
                Ok(m) => {
                    *out.add(0) = m[0][0];
                    *out.add(1) = m[0][1];
                    *out.add(2) = m[1][0];
                    *out.add(3) = m[1][1];
                    SidereonStatus::Ok
                }
                Err(err) => extra_invalid_arg("sidereon_encounter_plane_covariance", err),
            }
        },
    )
}

