/// Run RAIM over an SPP receiver solution handle (used satellites + post-fit
/// residuals come from the solution). weights/unit_weights/n_systems mirror
/// sidereon_raim. Delegates to sidereon_core::quality::raim_for_solution.
///
/// Safety: solution is a live SPP-solution handle; weights points to
/// weight_count SidereonFdeRaimWeight when unit_weights is false; out points to a
/// SidereonRaimResult.
#[no_mangle]
pub unsafe extern "C" fn sidereon_raim_for_solution(
    solution: *const SidereonSppSolution,
    p_fa: f64,
    unit_weights: bool,
    weights: *const SidereonFdeRaimWeight,
    weight_count: usize,
    n_systems_enabled: bool,
    n_systems: i64,
    out: *mut SidereonRaimResult,
) -> SidereonStatus {
    ffi_boundary("sidereon_raim_for_solution", SidereonStatus::Panic, || {
        let out = c_try!(require_out(out, "sidereon_raim_for_solution", "out"));
        *out = SidereonRaimResult {
            fault_detected: false,
            test_statistic: 0.0,
            has_threshold: false,
            threshold: 0.0,
            dof: 0,
            testable: false,
            has_worst_sat: false,
            worst_sat: [0; 17],
        };
        let solution = c_try!(require_ref(
            solution,
            "sidereon_raim_for_solution",
            "solution"
        ));
        let raim_weights = if unit_weights {
            RaimWeights::Unit
        } else {
            let rows = c_try!(require_slice(
                weights,
                weight_count,
                "sidereon_raim_for_solution",
                "weights"
            ));
            let mut map = BTreeMap::new();
            for row in rows {
                let sat = c_try!(parse_satellite_token(
                    "sidereon_raim_for_solution",
                    row.sat_id
                ));
                map.insert(sat.to_string(), row.weight);
            }
            RaimWeights::BySatellite(map)
        };
        let options = RaimOptions {
            p_fa,
            weights: raim_weights,
            n_systems: n_systems_enabled.then_some(n_systems as isize),
        };
        match sidereon_core::quality::raim_for_solution(&solution.inner, &options) {
            Ok(result) => {
                out.fault_detected = result.fault_detected;
                out.test_statistic = result.test_statistic;
                if let Some(t) = result.threshold {
                    out.has_threshold = true;
                    out.threshold = t;
                }
                out.dof = result.dof as i64;
                out.testable = result.testable;
                if let Some(worst) = result.worst_sat {
                    let bytes = worst.as_bytes();
                    if bytes.len() < SATELLITE_TOKEN_C_BYTES {
                        for (slot, b) in out.worst_sat.iter_mut().zip(bytes.iter()) {
                            *slot = *b as c_char;
                        }
                        out.worst_sat[bytes.len()] = 0;
                        out.has_worst_sat = true;
                    }
                }
                SidereonStatus::Ok
            }
            Err(err) => extra_invalid_arg("sidereon_raim_for_solution", err),
        }
    })
}

/// Receiver-solution plausibility-gate options, mirroring
/// sidereon_core::quality::SolutionValidationOptions.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonSolutionValidationOptions {
    /// Whether max_pdop is enforced.
    pub has_max_pdop: bool,
    /// PDOP ceiling when has_max_pdop is true.
    pub max_pdop: f64,
    /// Minimum plausible geocentric radius, meters.
    pub min_plausible_radius_m: f64,
    /// Maximum plausible geocentric radius, meters.
    pub max_plausible_radius_m: f64,
    /// Maximum plausible RMS for a converged solution, meters.
    pub max_converged_residual_rms_m: f64,
}

/// Fill *out_options with the engine default receiver-solution validation gates.
///
/// Safety: out_options must point to writable storage.
#[no_mangle]
pub unsafe extern "C" fn sidereon_solution_validation_options_init(
    out_options: *mut SidereonSolutionValidationOptions,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_solution_validation_options_init",
        SidereonStatus::Panic,
        || {
            let out_options = c_try!(require_out(
                out_options,
                "sidereon_solution_validation_options_init",
                "out_options"
            ));
            let d = SolutionValidationOptions::default();
            *out_options = SidereonSolutionValidationOptions {
                has_max_pdop: d.max_pdop.is_some(),
                max_pdop: d.max_pdop.unwrap_or(0.0),
                min_plausible_radius_m: d.min_plausible_radius_m,
                max_plausible_radius_m: d.max_plausible_radius_m,
                max_converged_residual_rms_m: d.max_converged_residual_rms_m,
            };
            SidereonStatus::Ok
        },
    )
}

/// Apply the receiver-solution plausibility gates to an SPP solution handle.
/// Returns SIDEREON_STATUS_OK when the solution passes; otherwise returns
/// SIDEREON_STATUS_INVALID_ARGUMENT and records the failing gate. Delegates to
/// sidereon_core::quality::validate_receiver_solution.
///
/// Safety: solution is a live SPP-solution handle; options points to a
/// SidereonSolutionValidationOptions.
#[no_mangle]
pub unsafe extern "C" fn sidereon_validate_receiver_solution(
    solution: *const SidereonSppSolution,
    options: *const SidereonSolutionValidationOptions,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_validate_receiver_solution",
        SidereonStatus::Panic,
        || {
            let solution = c_try!(require_ref(
                solution,
                "sidereon_validate_receiver_solution",
                "solution"
            ));
            let options = c_try!(require_ref(
                options,
                "sidereon_validate_receiver_solution",
                "options"
            ));
            let opts = SolutionValidationOptions {
                max_pdop: options.has_max_pdop.then_some(options.max_pdop),
                min_plausible_radius_m: options.min_plausible_radius_m,
                max_plausible_radius_m: options.max_plausible_radius_m,
                max_converged_residual_rms_m: options.max_converged_residual_rms_m,
            };
            match validate_receiver_solution(&solution.inner, opts) {
                Ok(()) => SidereonStatus::Ok,
                Err(err) => extra_invalid_arg("sidereon_validate_receiver_solution", err),
            }
        },
    )
}

// --- Cycle-slip detection (sidereon_core::carrier_phase) ---------------------

/// Cycle-slip classification for one input epoch, mirroring
/// sidereon_core::carrier_phase::SlipResult. reason_mask is a bitwise OR of the
/// SIDEREON_SLIP_REASON_* flags.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonSlipResult {
    /// Whether any slip reason was flagged.
    pub slip: bool,
    /// Bitmask of slip reasons (SIDEREON_SLIP_REASON_*).
    pub reason_mask: u32,
    /// Geometry-free phase, meters, or NaN when not computable.
    pub gf_m: f64,
    /// Melbourne-Wubbena combination, meters, or NaN when not computable.
    pub mw_m: f64,
    /// Whether the epoch was skipped (a frequency was unavailable).
    pub skipped: bool,
}

/// Slip reason: loss-of-lock indicator set.
pub const SIDEREON_SLIP_REASON_LLI: u32 = 1;
/// Slip reason: data gap exceeded the threshold.
pub const SIDEREON_SLIP_REASON_DATA_GAP: u32 = 2;
/// Slip reason: geometry-free phase step exceeded the threshold.
pub const SIDEREON_SLIP_REASON_GEOMETRY_FREE: u32 = 4;
/// Slip reason: Melbourne-Wubbena step exceeded the threshold.
pub const SIDEREON_SLIP_REASON_MELBOURNE_WUBBENA: u32 = 8;

fn slip_reason_mask(reasons: &[sidereon_core::carrier_phase::SlipReason]) -> u32 {
    use sidereon_core::carrier_phase::SlipReason;
    let mut mask = 0u32;
    for reason in reasons {
        mask |= match reason {
            SlipReason::Lli => SIDEREON_SLIP_REASON_LLI,
            SlipReason::DataGap => SIDEREON_SLIP_REASON_DATA_GAP,
            SlipReason::GeometryFree => SIDEREON_SLIP_REASON_GEOMETRY_FREE,
            SlipReason::MelbourneWubbena => SIDEREON_SLIP_REASON_MELBOURNE_WUBBENA,
        };
    }
    mask
}

/// Classify cycle slips over a single-satellite carrier-phase arc. One result is
/// produced per input epoch. Variable-length output contract. Delegates to
/// sidereon_core::carrier_phase::detect_cycle_slips.
///
/// Safety: arc points to count SidereonArcEpoch; options to a
/// SidereonCycleSlipOptions; out to len SidereonSlipResult or NULL when len is 0;
/// out_written and out_required point to size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_detect_cycle_slips(
    arc: *const SidereonArcEpoch,
    count: usize,
    options: *const SidereonCycleSlipOptions,
    out: *mut SidereonSlipResult,
    len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary("sidereon_detect_cycle_slips", SidereonStatus::Panic, || {
        c_try!(init_copy_counts(
            "sidereon_detect_cycle_slips",
            out_written,
            out_required
        ));
        let (arc, opts) = c_try!(arc_from_c(
            "sidereon_detect_cycle_slips",
            arc,
            count,
            options
        ));
        let results = match sidereon_core::carrier_phase::detect_cycle_slips(&arc, opts) {
            Ok(r) => r,
            Err(err) => return extra_invalid_arg("sidereon_detect_cycle_slips", err),
        };
        let mapped: Vec<SidereonSlipResult> = results
            .iter()
            .map(|r| SidereonSlipResult {
                slip: r.slip,
                reason_mask: slip_reason_mask(&r.reasons),
                gf_m: none_to_nan(r.gf_m),
                mw_m: none_to_nan(r.mw_m),
                skipped: r.skipped,
            })
            .collect();
        c_try!(copy_prefix_to_c(
            "sidereon_detect_cycle_slips",
            "out",
            &mapped,
            out,
            len,
            out_written,
            out_required,
        ));
        SidereonStatus::Ok
    })
}

