// ============================================================================
// Newly merged core features: full NeQuick-G slant integration, the standalone
// range RAIM/FDE design, the RTK and PPP arc drivers, and RTCM 3 from-scratch
// message construction. Every function below marshals C input into the cited
// sidereon-core type, calls the engine entry point, and copies the result back.
// No modeling lives here.
// ============================================================================

// --- NeQuick-G full slant integration (sidereon_core::atmosphere::ionosphere) -

/// Receiver/satellite ray geometry and epoch for a full NeQuick-G evaluation,
/// mirroring sidereon_core::atmosphere::ionosphere::NequickGRayEval. Geodetic
/// longitudes and latitudes are in degrees, heights in metres above the
/// reference sphere; `month` is 1..=12 and `utc_hours` is in [0, 24].
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonNequickGRay {
    /// Month of the year, 1..=12.
    pub month: u8,
    /// UTC time of day in hours, [0, 24].
    pub utc_hours: f64,
    /// Receiver geodetic longitude, degrees.
    pub station_lon_deg: f64,
    /// Receiver geodetic latitude, degrees.
    pub station_lat_deg: f64,
    /// Receiver height above the reference sphere, metres.
    pub station_height_m: f64,
    /// Satellite geodetic longitude, degrees.
    pub satellite_lon_deg: f64,
    /// Satellite geodetic latitude, degrees.
    pub satellite_lat_deg: f64,
    /// Satellite height above the reference sphere, metres.
    pub satellite_height_m: f64,
}

fn nequick_g_ray_from_c(ray: &SidereonNequickGRay) -> NequickGRayEval {
    NequickGRayEval {
        month: ray.month,
        utc_hours: ray.utc_hours,
        station_lon_deg: ray.station_lon_deg,
        station_lat_deg: ray.station_lat_deg,
        station_height_m: ray.station_height_m,
        satellite_lon_deg: ray.satellite_lon_deg,
        satellite_lat_deg: ray.satellite_lat_deg,
        satellite_height_m: ray.satellite_height_m,
    }
}

/// Full NeQuick-G slant total electron content along the ray, in TECU. Delegates
/// to sidereon_core::atmosphere::ionosphere::nequick_g_stec_tecu.
///
/// `ai0`/`ai1`/`ai2` are the three Galileo broadcast effective-ionisation
/// coefficients. Writes the slant TEC to *out_stec_tecu.
///
/// Safety: ray must point to a SidereonNequickGRay; out_stec_tecu to a double.
#[no_mangle]
pub unsafe extern "C" fn sidereon_nequick_g_stec_tecu(
    ai0: f64,
    ai1: f64,
    ai2: f64,
    ray: *const SidereonNequickGRay,
    out_stec_tecu: *mut f64,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_nequick_g_stec_tecu",
        SidereonStatus::Panic,
        || {
            let out_stec_tecu = c_try!(require_out(
                out_stec_tecu,
                "sidereon_nequick_g_stec_tecu",
                "out_stec_tecu"
            ));
            *out_stec_tecu = 0.0;
            let ray = c_try!(require_ref(ray, "sidereon_nequick_g_stec_tecu", "ray"));
            let coeffs = GalileoNequickCoeffs { ai0, ai1, ai2 };
            match nequick_g_stec_tecu(&coeffs, &nequick_g_ray_from_c(ray)) {
                Ok(stec) => {
                    *out_stec_tecu = stec;
                    SidereonStatus::Ok
                }
                Err(err) => map_iono_error("sidereon_nequick_g_stec_tecu", err),
            }
        },
    )
}

/// Full NeQuick-G slant ionospheric group delay (positive metres) on
/// `frequency_hz`. Delegates to
/// sidereon_core::atmosphere::ionosphere::nequick_g_delay_m.
///
/// Safety: ray must point to a SidereonNequickGRay; out_delay_m to a double.
#[no_mangle]
pub unsafe extern "C" fn sidereon_nequick_g_delay_m(
    ai0: f64,
    ai1: f64,
    ai2: f64,
    ray: *const SidereonNequickGRay,
    frequency_hz: f64,
    out_delay_m: *mut f64,
) -> SidereonStatus {
    ffi_boundary("sidereon_nequick_g_delay_m", SidereonStatus::Panic, || {
        let out_delay_m = c_try!(require_out(
            out_delay_m,
            "sidereon_nequick_g_delay_m",
            "out_delay_m"
        ));
        *out_delay_m = 0.0;
        let ray = c_try!(require_ref(ray, "sidereon_nequick_g_delay_m", "ray"));
        let coeffs = GalileoNequickCoeffs { ai0, ai1, ai2 };
        match nequick_g_delay_m(&coeffs, &nequick_g_ray_from_c(ray), frequency_hz) {
            Ok(delay) => {
                *out_delay_m = delay;
                SidereonStatus::Ok
            }
            Err(err) => map_iono_error("sidereon_nequick_g_delay_m", err),
        }
    })
}

// --- Standalone range RAIM/FDE design (sidereon_core::quality) ----------------

/// One linearized range measurement for sidereon_raim_fde_design, mirroring
/// sidereon_core::quality::RangeFdeRow. `design_row` points to `design_dim`
/// doubles (the design-matrix row); every row must carry the same `design_dim`,
/// which is the estimated state dimension.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonRangeFdeRow {
    /// Stable measurement identifier (e.g. a satellite token "G01").
    pub id: *const c_char,
    /// Observed-minus-computed range residual, metres.
    pub residual_m: f64,
    /// Design-matrix row: partials with respect to each estimated state parameter.
    pub design_row: *const f64,
    /// Length of `design_row`, the estimated state dimension.
    pub design_dim: usize,
    /// Inverse-variance weight 1/sigma^2; must be finite and strictly positive.
    pub weight: f64,
}

/// Options for sidereon_raim_fde_design, mirroring
/// sidereon_core::quality::RangeFdeOptions. Initialize with
/// sidereon_range_fde_options_init, then override fields.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonRangeFdeOptions {
    /// False-alarm probability for the global chi-square test, in (0, 1).
    pub p_fa: f64,
    /// Maximum number of measurements the exclusion loop may remove.
    pub max_exclusions: usize,
    /// Minimum redundancy (degrees of freedom) an exclusion must leave behind.
    pub min_redundancy: usize,
}

/// Global chi-square consistency test, mirroring
/// sidereon_core::quality::RangeChiSquareTest.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonRangeChiSquareTest {
    /// Weighted sum of squared post-fit residuals, v^T W v.
    pub weighted_sum_squares: f64,
    /// Redundancy n_used - n_state.
    pub dof: i64,
    /// Whether a chi-square threshold is present (true when dof > 0).
    pub has_threshold: bool,
    /// Chi-square threshold chi2_inv(1 - p_fa, dof), 0 when absent.
    pub threshold: f64,
    /// False when dof <= 0 (no redundancy to test against).
    pub testable: bool,
    /// True when the test statistic exceeds the threshold (a fault remains).
    pub fault_detected: bool,
}

/// Per-measurement FDE diagnostic, mirroring
/// sidereon_core::quality::RangeMeasurementDiagnostic, in input order.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonRangeFdeDiagnostic {
    /// Measurement identifier, echoed from the input row.
    pub id: SidereonRtkId,
    /// Whether the FDE loop excluded this measurement.
    pub excluded: bool,
    /// Post-fit residual against the protected state correction, metres.
    pub post_fit_residual_m: f64,
    /// Standardized post-fit residual post_fit_residual_m * sqrt(weight).
    pub normalized_residual: f64,
}

/// Result of sidereon_raim_fde_design. Opaque to C. Read with the
/// sidereon_range_fde_result_* accessors; release with
/// sidereon_range_fde_result_free.
pub struct SidereonRangeFdeResult {
    inner: RangeFdeResult,
}

fn map_quality_error(fn_name: &str, err: QualityError) -> SidereonStatus {
    set_last_error(format!("{fn_name}: {err}"));
    match err {
        QualityError::SingularGeometry => SidereonStatus::Solve,
        _ => SidereonStatus::InvalidArgument,
    }
}

/// Initialize SidereonRangeFdeOptions with the engine defaults (RTKLIB demo5
/// p_fa, unbounded exclusions, minimum redundancy 1).
///
/// Safety: options must point to a writable SidereonRangeFdeOptions.
#[no_mangle]
pub unsafe extern "C" fn sidereon_range_fde_options_init(
    options: *mut SidereonRangeFdeOptions,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_range_fde_options_init",
        SidereonStatus::Panic,
        || {
            let options = c_try!(require_out(
                options,
                "sidereon_range_fde_options_init",
                "options"
            ));
            let defaults = RangeFdeOptions::default();
            *options = SidereonRangeFdeOptions {
                p_fa: defaults.p_fa,
                max_exclusions: defaults.max_exclusions,
                min_redundancy: defaults.min_redundancy,
            };
            SidereonStatus::Ok
        },
    )
}

unsafe fn range_fde_rows_from_c(
    fn_name: &str,
    rows: *const SidereonRangeFdeRow,
    row_count: usize,
) -> Result<Vec<RangeFdeRow>, SidereonStatus> {
    let raw_rows = require_slice(rows, row_count, fn_name, "rows")?;
    validate_element_count::<RangeFdeRow>(fn_name, "row_count", raw_rows.len())?;
    let mut out = Vec::with_capacity(raw_rows.len());
    for (idx, row) in raw_rows.iter().enumerate() {
        let id = parse_bounded_c_string(
            fn_name,
            &format!("rows[{idx}].id"),
            row.id,
            MAX_RTK_ID_BYTES,
        )?;
        let design_row = require_slice(
            row.design_row,
            row.design_dim,
            fn_name,
            &format!("rows[{idx}].design_row"),
        )?;
        out.push(RangeFdeRow {
            id,
            residual_m: row.residual_m,
            design_row: design_row.to_vec(),
            weight: row.weight,
        });
    }
    Ok(out)
}

/// Run the standalone range RAIM/FDE over a linearized measurement set. On
/// success writes a newly owned result handle to *out_result. Release it with
/// sidereon_range_fde_result_free. Delegates to
/// sidereon_core::quality::raim_fde_design.
///
/// Safety: rows points to row_count SidereonRangeFdeRow (or NULL when 0);
/// options points to a SidereonRangeFdeOptions; out_result to a
/// SidereonRangeFdeResult*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_raim_fde_design(
    rows: *const SidereonRangeFdeRow,
    row_count: usize,
    options: *const SidereonRangeFdeOptions,
    out_result: *mut *mut SidereonRangeFdeResult,
) -> SidereonStatus {
    ffi_boundary("sidereon_raim_fde_design", SidereonStatus::Panic, || {
        let out_result = c_try!(require_out(
            out_result,
            "sidereon_raim_fde_design",
            "out_result"
        ));
        *out_result = ptr::null_mut();
        let options = c_try!(require_ref(options, "sidereon_raim_fde_design", "options"));
        let rows = c_try!(range_fde_rows_from_c(
            "sidereon_raim_fde_design",
            rows,
            row_count
        ));
        let core_options = RangeFdeOptions {
            p_fa: options.p_fa,
            max_exclusions: options.max_exclusions,
            min_redundancy: options.min_redundancy,
        };
        match raim_fde_design(&rows, &core_options) {
            Ok(inner) => {
                write_boxed_handle(out_result, SidereonRangeFdeResult { inner });
                SidereonStatus::Ok
            }
            Err(err) => map_quality_error("sidereon_raim_fde_design", err),
        }
    })
}

