// --- PPP auto-initialization driver (sidereon_core::precise_positioning) ------

/// SPP-seeded auto-initialization policy for the raw-epochs PPP driver, mirroring
/// sidereon_core::precise_positioning::PppAutoInitOptions. Initialize with
/// sidereon_ppp_auto_init_options_init, then override fields.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonPppAutoInitOptions {
    /// When true, the explicit position/clock seed below bypasses the SPP/mean
    /// auto-init stages entirely.
    pub has_initial_guess: bool,
    /// Explicit static receiver position seed (ECEF metres), used when
    /// has_initial_guess is true.
    pub initial_guess_position_m: [f64; 3],
    /// Explicit receiver clock seed (metres), duplicated across every epoch.
    pub initial_guess_clock_m: f64,
    /// SPP cold-start guess [x_m, y_m, z_m, b_m] for every per-epoch seed solve.
    pub spp_initial_guess: [f64; 4],
    /// Apply the troposphere correction in the SPP seed solve. The ionosphere is
    /// always off in the seed.
    pub spp_troposphere: bool,
    /// SPP seed surface pressure (hPa).
    pub spp_pressure_hpa: f64,
    /// SPP seed surface temperature (K).
    pub spp_temperature_k: f64,
    /// SPP seed surface relative humidity, fraction in [0, 1].
    pub spp_relative_humidity: f64,
}

/// Initialize SidereonPppAutoInitOptions with the engine defaults (no explicit
/// guess, an all-zero SPP cold start, the troposphere off, standard surface
/// meteorology).
///
/// Safety: options must point to a writable SidereonPppAutoInitOptions.
#[no_mangle]
pub unsafe extern "C" fn sidereon_ppp_auto_init_options_init(
    options: *mut SidereonPppAutoInitOptions,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_ppp_auto_init_options_init",
        SidereonStatus::Panic,
        || {
            let options = c_try!(require_out(
                options,
                "sidereon_ppp_auto_init_options_init",
                "options"
            ));
            let defaults = PppAutoInitOptions::default();
            *options = SidereonPppAutoInitOptions {
                has_initial_guess: defaults.initial_guess.is_some(),
                initial_guess_position_m: defaults
                    .initial_guess
                    .map(|g| g.position_m)
                    .unwrap_or([0.0; 3]),
                initial_guess_clock_m: defaults.initial_guess.map(|g| g.clock_m).unwrap_or(0.0),
                spp_initial_guess: defaults.spp_initial_guess,
                spp_troposphere: defaults.spp_troposphere,
                spp_pressure_hpa: defaults.spp_met.pressure_hpa,
                spp_temperature_k: defaults.spp_met.temperature_k,
                spp_relative_humidity: defaults.spp_met.relative_humidity,
            };
            SidereonStatus::Ok
        },
    )
}

fn ppp_auto_init_options_from_c(options: &SidereonPppAutoInitOptions) -> PppAutoInitOptions {
    PppAutoInitOptions {
        initial_guess: options.has_initial_guess.then_some(PppInitialGuess {
            position_m: options.initial_guess_position_m,
            clock_m: options.initial_guess_clock_m,
        }),
        spp_initial_guess: options.spp_initial_guess,
        spp_troposphere: options.spp_troposphere,
        spp_met: SurfaceMet {
            pressure_hpa: options.spp_pressure_hpa,
            temperature_k: options.spp_temperature_k,
            relative_humidity: options.spp_relative_humidity,
        },
    }
}

/// Solve a static multi-epoch float PPP arc from raw epochs, auto-initializing
/// the float state from the SPP seed (no caller initial FloatState needed). The
/// epochs and float settings come from `float_config` (its `initial_state` is
/// ignored). On success writes a newly owned solution handle to *out_solution;
/// release it with sidereon_ppp_float_solution_free. Delegates to
/// sidereon_core::precise_positioning::solve_ppp_auto_init_float.
///
/// Safety: sp3, float_config, and options must point to live handles/structs;
/// out_solution must point to storage for a SidereonPppFloatSolution*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_solve_ppp_auto_init_float(
    sp3: *const SidereonSp3,
    float_config: *const SidereonPppFloatConfig,
    options: *const SidereonPppAutoInitOptions,
    out_solution: *mut *mut SidereonPppFloatSolution,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_solve_ppp_auto_init_float",
        SidereonStatus::Panic,
        || {
            let out_solution = c_try!(require_out(
                out_solution,
                "sidereon_solve_ppp_auto_init_float",
                "out_solution"
            ));
            *out_solution = ptr::null_mut();
            let sp3 = c_try!(require_ref(
                sp3,
                "sidereon_solve_ppp_auto_init_float",
                "sp3"
            ));
            let float_config = c_try!(require_ref(
                float_config,
                "sidereon_solve_ppp_auto_init_float",
                "float_config"
            ));
            let options = c_try!(require_ref(
                options,
                "sidereon_solve_ppp_auto_init_float",
                "options"
            ));
            let epochs = c_try!(ppp_epochs_from_c(
                "sidereon_solve_ppp_auto_init_float",
                float_config.epochs,
                float_config.epoch_count,
            ));
            let solve_config = c_try!(ppp_float_config_from_c(
                "sidereon_solve_ppp_auto_init_float",
                float_config
            ));
            let auto_options = ppp_auto_init_options_from_c(options);
            let inner =
                match solve_ppp_auto_init_float(&sp3.inner, &epochs, auto_options, solve_config) {
                    Ok(inner) => inner,
                    Err(err) => {
                        set_last_error(format!("sidereon_solve_ppp_auto_init_float: {err}"));
                        return SidereonStatus::Solve;
                    }
                };
            write_boxed_handle(out_solution, SidereonPppFloatSolution { inner });
            SidereonStatus::Ok
        },
    )
}

/// Solve a static integer-fixed PPP arc from raw epochs: the SPP auto-init seed,
/// the float solve, then the LAMBDA integer fix and ambiguity-conditioned
