// --- CRINEX encode (sidereon_core::crinex::encode_crinex) --------------------

/// Encode RINEX observation text into CRINEX (Hatanaka-compressed) text. The
/// output is not null-terminated and is byte-for-byte what rnx2crx produces. Uses
/// the variable-length output contract. Delegates to
/// sidereon_core::crinex::encode_crinex.
///
/// Safety: data points to len readable bytes; out points to at least out_len
/// writable bytes or NULL when out_len is 0; out_written and out_required point to
/// size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_crinex_encode(
    data: *const u8,
    len: usize,
    out: *mut u8,
    out_len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary("sidereon_crinex_encode", SidereonStatus::Panic, || {
        c_try!(init_copy_counts(
            "sidereon_crinex_encode",
            out_written,
            out_required
        ));
        let bytes = c_try!(require_slice(data, len, "sidereon_crinex_encode", "data"));
        let text = match str::from_utf8(bytes) {
            Ok(text) => text,
            Err(_) => {
                set_last_error("sidereon_crinex_encode: data is not valid UTF-8".to_string());
                return SidereonStatus::InvalidToken;
            }
        };
        let encoded = match sidereon_core::rinex::crinex::encode_crinex(text) {
            Ok(encoded) => encoded,
            Err(err) => {
                set_last_error(format!("sidereon_crinex_encode: {err}"));
                return SidereonStatus::InvalidArgument;
            }
        };
        c_try!(copy_prefix_to_c(
            "sidereon_crinex_encode",
            "out",
            encoded.as_bytes(),
            out,
            out_len,
            out_written,
            out_required,
        ));
        SidereonStatus::Ok
    })
}

// --- Broadcast-vs-precise comparison over a sampled window -------------------

/// A regularly sampled comparison window, mirroring
/// sidereon_core::broadcast_comparison::CompareWindow. The broadcast product is
/// queried on the continuous J2000-second axis; the precise product is queried by
/// split Julian date advanced from precise_start in lockstep.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonCompareWindow {
    /// Inclusive broadcast query window start, continuous seconds since J2000.
    pub broadcast_window_start_j2000_s: f64,
    /// Inclusive broadcast query window end, continuous seconds since J2000.
    pub broadcast_window_end_j2000_s: f64,
    /// Precise query for the window start, whole Julian day.
    pub precise_start_jd_whole: f64,
    /// Precise query for the window start, Julian-day fraction.
    pub precise_start_jd_fraction: f64,
    /// Sampling step between consecutive epochs, seconds.
    pub step_s: f64,
    /// Velocity finite-difference half step, seconds.
    pub velocity_half_s: f64,
}

/// Compare a broadcast ephemeris against a precise SP3 product over a sampled
/// window. On success writes a newly owned report handle (read with the
/// sidereon_broadcast_comparison_* accessors, released with
/// sidereon_broadcast_comparison_free). Delegates to
/// sidereon_core::broadcast_comparison::compare_window.
///
/// Safety: broadcast and precise are live handles; satellites points to
/// satellite_count null-terminated tokens; window points to a
/// SidereonCompareWindow; out_report points to a SidereonBroadcastComparison*.
#[no_mangle]
pub unsafe extern "C" fn sidereon_broadcast_comparison_compare_window(
    broadcast: *const SidereonBroadcastEphemeris,
    precise: *const SidereonSp3,
    satellites: *const *const c_char,
    satellite_count: usize,
    window: *const SidereonCompareWindow,
    out_report: *mut *mut SidereonBroadcastComparison,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_broadcast_comparison_compare_window",
        SidereonStatus::Panic,
        || {
            let fn_name = "sidereon_broadcast_comparison_compare_window";
            let out_report = c_try!(require_out(out_report, fn_name, "out_report"));
            *out_report = ptr::null_mut();
            let broadcast = c_try!(require_ref(broadcast, fn_name, "broadcast"));
            let precise = c_try!(require_ref(precise, fn_name, "precise"));
            let window = c_try!(require_ref(window, fn_name, "window"));
            let sat_ptrs = c_try!(require_slice(
                satellites,
                satellite_count,
                fn_name,
                "satellites"
            ));
            let mut sats = Vec::with_capacity(satellite_count);
            for ptr in sat_ptrs {
                sats.push(c_try!(parse_satellite_token(fn_name, *ptr)));
            }
            let precise_start = c_try!(sidereon_core::astro::time::JulianDateSplit::new(
                window.precise_start_jd_whole,
                window.precise_start_jd_fraction
            )
            .map_err(|err| extra_invalid_arg(fn_name, err)));
            let core_window = sidereon_core::broadcast_comparison::CompareWindow {
                broadcast_window_j2000_s: (
                    window.broadcast_window_start_j2000_s,
                    window.broadcast_window_end_j2000_s,
                ),
                precise_start,
                step_s: window.step_s,
                velocity_half_s: window.velocity_half_s,
            };
            match sidereon_core::broadcast_comparison::compare_window(
                &broadcast.inner,
                &precise.inner,
                &sats,
                &core_window,
            ) {
                Ok(report) => {
                    write_boxed_handle(out_report, SidereonBroadcastComparison { inner: report });
                    SidereonStatus::Ok
                }
                Err(err) => {
                    set_last_error(format!("{fn_name}: {err}"));
                    SidereonStatus::InvalidArgument
                }
            }
        },
    )
}

// --- RTK arc per-epoch innovation screen ------------------------------------

/// One epoch's predicted-residual innovation-screen diagnostics, mirroring
/// sidereon_core::rtk_filter::InnovationScreen. The two max fields are NaN when
/// no row populated them. Read with sidereon_rtk_arc_solution_epoch_innovation_screen,
/// whose out_present flag reports whether the screen ran this epoch.
#[repr(C)]
#[derive(Clone, Copy)]
pub struct SidereonRtkInnovationScreen {
    /// Rejection threshold (sigmas).
    pub threshold_sigma: f64,
    /// Minimum row count required to run the screen.
    pub min_rows: usize,
    /// Rows presented to the screen.
    pub input_rows: usize,
    /// Rows accepted.
    pub accepted_rows: usize,
    /// Rows rejected.
    pub rejected_rows: usize,
    /// Code rows rejected.
    pub rejected_code_rows: usize,
    /// Phase rows rejected.
    pub rejected_phase_rows: usize,
    /// Maximum absolute normalized innovation over all rows (NaN if none).
    pub max_abs_normalized_innovation: f64,
    /// Maximum absolute normalized innovation over rejected rows (NaN if none).
    pub max_rejected_abs_normalized_innovation: f64,
    /// Whether the epoch coasted (screen rejected enough to skip the update).
    pub coasted: bool,
}

/// Copy one epoch's innovation-screen diagnostics into *out and set *out_present
/// to whether the screen ran this epoch (it is absent when disabled in the arc
/// update options). When absent, *out is zeroed and *out_present is false.
///
/// Safety: solution is a live handle; out points to a SidereonRtkInnovationScreen;
/// out_present points to a bool.
#[no_mangle]
pub unsafe extern "C" fn sidereon_rtk_arc_solution_epoch_innovation_screen(
    solution: *const SidereonRtkArcSolution,
    index: usize,
    out: *mut SidereonRtkInnovationScreen,
    out_present: *mut bool,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_rtk_arc_solution_epoch_innovation_screen",
        SidereonStatus::Panic,
        || {
            let fn_name = "sidereon_rtk_arc_solution_epoch_innovation_screen";
            let out = c_try!(require_out(out, fn_name, "out"));
            *out = SidereonRtkInnovationScreen {
                threshold_sigma: 0.0,
                min_rows: 0,
                input_rows: 0,
                accepted_rows: 0,
                rejected_rows: 0,
                rejected_code_rows: 0,
                rejected_phase_rows: 0,
                max_abs_normalized_innovation: f64::NAN,
                max_rejected_abs_normalized_innovation: f64::NAN,
                coasted: false,
            };
            let out_present = c_try!(require_out(out_present, fn_name, "out_present"));
            *out_present = false;
            let epoch = c_try!(rtk_arc_epoch_at(fn_name, solution, index));
            if let Some(screen) = epoch.innovation_screen.as_ref() {
                *out = SidereonRtkInnovationScreen {
                    threshold_sigma: screen.threshold_sigma,
                    min_rows: screen.min_rows,
                    input_rows: screen.input_rows,
                    accepted_rows: screen.accepted_rows,
                    rejected_rows: screen.rejected_rows,
                    rejected_code_rows: screen.rejected_code_rows,
                    rejected_phase_rows: screen.rejected_phase_rows,
                    max_abs_normalized_innovation: none_to_nan(
                        screen.max_abs_normalized_innovation,
                    ),
                    max_rejected_abs_normalized_innovation: none_to_nan(
                        screen.max_rejected_abs_normalized_innovation,
                    ),
                    coasted: screen.coasted,
                };
                *out_present = true;
            }
            SidereonStatus::Ok
        },
    )
}

// --- CDM comprehensive metadata + velocity covariance -----------------------

/// Selects which per-object CDM metadata string field a reader returns. Pass to
/// sidereon_cdm_object_string_field as a uint32_t. Mirrors the CCSDS 508.0-B-1
/// object metadata block order.
#[repr(C)]
#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum SidereonCdmObjectStringField {
    /// OBJECT_DESIGNATOR.
    ObjectDesignator = 0,
    /// CATALOG_NAME.
    CatalogName = 1,
    /// OBJECT_NAME.
    ObjectName = 2,
    /// INTERNATIONAL_DESIGNATOR.
    InternationalDesignator = 3,
    /// OBJECT_TYPE.
    ObjectType = 4,
    /// OPERATOR_CONTACT_POSITION.
    OperatorContactPosition = 5,
    /// OPERATOR_ORGANIZATION.
    OperatorOrganization = 6,
    /// OPERATOR_PHONE.
    OperatorPhone = 7,
    /// OPERATOR_EMAIL.
    OperatorEmail = 8,
    /// EPHEMERIS_NAME.
    EphemerisName = 9,
    /// COVARIANCE_METHOD.
    CovarianceMethod = 10,
    /// MANEUVERABLE.
    Maneuverable = 11,
    /// ORBIT_CENTER.
    OrbitCenter = 12,
    /// REF_FRAME.
    RefFrame = 13,
    /// GRAVITY_MODEL.
    GravityModel = 14,
    /// ATMOSPHERIC_MODEL.
    AtmosphericModel = 15,
    /// N_BODY_PERTURBATIONS.
    NBodyPerturbations = 16,
    /// SOLAR_RAD_PRESSURE.
    SolarRadPressure = 17,
    /// EARTH_TIDES.
    EarthTides = 18,
    /// INTRACK_THRUST.
    IntrackThrust = 19,
}

/// Read one CDM object's metadata string field selected by
/// SidereonCdmObjectStringField into a caller buffer (not null-terminated).
/// object_index must be 1 or 2. An absent optional field reports *out_required 0
/// and writes nothing. Variable-length output contract.
///
/// Safety: cdm is a live handle; out points to len writable bytes or NULL when
/// len is 0; out_written and out_required point to size_t.
#[no_mangle]
pub unsafe extern "C" fn sidereon_cdm_object_string_field(
    cdm: *const SidereonCdm,
    object_index: u32,
    field: u32,
    out: *mut u8,
    len: usize,
    out_written: *mut usize,
    out_required: *mut usize,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_cdm_object_string_field",
        SidereonStatus::Panic,
        || {
            let fn_name = "sidereon_cdm_object_string_field";
            c_try!(init_copy_counts(fn_name, out_written, out_required));
            let cdm = c_try!(require_ref(cdm, fn_name, "cdm"));
            let obj = match object_index {
                1 => &cdm.inner.object1,
                2 => &cdm.inner.object2,
                _ => {
                    set_last_error(format!("{fn_name}: object_index must be 1 or 2"));
                    return SidereonStatus::InvalidArgument;
                }
            };
            let value: Option<&str> = match field {
                v if v == SidereonCdmObjectStringField::ObjectDesignator as u32 => {
                    obj.object_designator.as_deref()
                }
                v if v == SidereonCdmObjectStringField::CatalogName as u32 => {
                    obj.catalog_name.as_deref()
                }
                v if v == SidereonCdmObjectStringField::ObjectName as u32 => {
                    obj.object_name.as_deref()
                }
                v if v == SidereonCdmObjectStringField::InternationalDesignator as u32 => {
                    obj.international_designator.as_deref()
                }
                v if v == SidereonCdmObjectStringField::ObjectType as u32 => {
                    obj.object_type.as_deref()
                }
                v if v == SidereonCdmObjectStringField::OperatorContactPosition as u32 => {
                    obj.operator_contact_position.as_deref()
                }
                v if v == SidereonCdmObjectStringField::OperatorOrganization as u32 => {
                    obj.operator_organization.as_deref()
                }
                v if v == SidereonCdmObjectStringField::OperatorPhone as u32 => {
                    obj.operator_phone.as_deref()
                }
                v if v == SidereonCdmObjectStringField::OperatorEmail as u32 => {
                    obj.operator_email.as_deref()
                }
                v if v == SidereonCdmObjectStringField::EphemerisName as u32 => {
                    obj.ephemeris_name.as_deref()
                }
                v if v == SidereonCdmObjectStringField::CovarianceMethod as u32 => {
                    obj.covariance_method.as_deref()
                }
                v if v == SidereonCdmObjectStringField::Maneuverable as u32 => {
                    obj.maneuverable.as_deref()
                }
                v if v == SidereonCdmObjectStringField::OrbitCenter as u32 => {
                    obj.orbit_center.as_deref()
                }
                v if v == SidereonCdmObjectStringField::RefFrame as u32 => obj.ref_frame.as_deref(),
                v if v == SidereonCdmObjectStringField::GravityModel as u32 => {
                    obj.gravity_model.as_deref()
                }
                v if v == SidereonCdmObjectStringField::AtmosphericModel as u32 => {
                    obj.atmospheric_model.as_deref()
                }
                v if v == SidereonCdmObjectStringField::NBodyPerturbations as u32 => {
                    obj.n_body_perturbations.as_deref()
                }
                v if v == SidereonCdmObjectStringField::SolarRadPressure as u32 => {
                    obj.solar_rad_pressure.as_deref()
                }
                v if v == SidereonCdmObjectStringField::EarthTides as u32 => {
                    obj.earth_tides.as_deref()
                }
                v if v == SidereonCdmObjectStringField::IntrackThrust as u32 => {
                    obj.intrack_thrust.as_deref()
                }
                _ => {
                    set_last_error(format!("{fn_name}: invalid field code"));
                    return SidereonStatus::InvalidArgument;
                }
            };
            let bytes = value.unwrap_or("").as_bytes();
            c_try!(copy_prefix_to_c(
                fn_name,
                "out",
                bytes,
                out,
                len,
                out_written,
                out_required,
            ));
            SidereonStatus::Ok
        },
    )
}

/// Copy one CDM object's RTN velocity-covariance block (the 15 lower-triangle
/// elements completing the 6x6 matrix) into out_covariance and set *out_present
/// to whether the producer carried the full velocity block. object_index must be
/// 1 or 2. When absent, out_covariance is zeroed and *out_present is false.
///
/// Safety: cdm is a live handle; out_covariance points to 15 writable doubles;
/// out_present points to a bool.
#[no_mangle]
pub unsafe extern "C" fn sidereon_cdm_object_velocity_covariance(
    cdm: *const SidereonCdm,
    object_index: u32,
    out_covariance: *mut f64,
    out_present: *mut bool,
) -> SidereonStatus {
    ffi_boundary(
        "sidereon_cdm_object_velocity_covariance",
        SidereonStatus::Panic,
        || {
            let fn_name = "sidereon_cdm_object_velocity_covariance";
            let out_present = c_try!(require_out(out_present, fn_name, "out_present"));
            *out_present = false;
            let cdm = c_try!(require_ref(cdm, fn_name, "cdm"));
            let obj = match object_index {
                1 => &cdm.inner.object1,
                2 => &cdm.inner.object2,
                _ => {
                    set_last_error(format!("{fn_name}: object_index must be 1 or 2"));
                    return SidereonStatus::InvalidArgument;
                }
            };
            let values = obj.velocity_covariance_rtn.unwrap_or([0.0; 15]);
            c_try!(copy_exact_f64s(
                fn_name,
                "out_covariance",
                out_covariance,
                15,
                &values,
            ));
            *out_present = obj.velocity_covariance_rtn.is_some();
            SidereonStatus::Ok
        },
    )
}

